insert into public.if_tips (slug, category, title, body, phases, sport_day, heavy, action, evidence) values
('fys-a-01','fysiologie','Je maag is binnen een paar uur leeg','Na je laatste maaltijd is je maag binnen twee tot vier uur grotendeels leeg. Wat je daarna voelt is niet per se honger door een tekort, maar een lege maag die eraan gewend is rond deze tijd iets te krijgen. Je lichaam teert ondertussen op wat je al gegeten hebt. De brandstof zit er nog. Alleen de maag is leeg, en dat is iets anders dan zonder energie zitten.',array['fast_early']::text[],null,false,null,null),
('fys-a-02','fysiologie','Waarom insuline daalt zodra je stopt met eten','Elke keer dat je eet, stijgt je insuline. Dat hormoon regelt dat suiker uit je bloed in je cellen komt en zet je lichaam in opslagstand. Zolang je niet eet, zakt de insuline langzaam terug. Dat is precies het punt van vasten: je geeft je lichaam uren waarin het niet bezig is met opslaan. Je merkt er zelf weinig van. Het gebeurt stil, onder de motorkap, in de eerste uren nadat je bord leeg was.',array['fast_early']::text[],null,false,null,null),
('fys-a-03','fysiologie','Je lever heeft een voorraadkast','Je lever slaat suiker op als glycogeen. Tussen maaltijden, en zeker in de eerste uren van je vast, tapt hij daar rustig van af om je bloedsuiker op peil te houden. Die voorraad gaat een tijd mee, grofweg een halve dag tot een dag, afhankelijk van hoe actief je bent. Zolang die kast nog gevuld is, hoef je nergens bang voor te zijn als je een paar uur niet eet. Er is genoeg achter de hand.',array['fast_early','fast_mid']::text[],null,false,null,null),
('fys-a-04','fysiologie','Je bloedsuiker stort niet zomaar in','Veel mensen denken dat ze zonder ontbijt onderuitgaan door een suikerdip. Bij een gezond lichaam gebeurt dat niet. Je lever geeft gestaag suiker af, en samen met een aantal hormonen houdt je lichaam de bloedsuiker binnen een smalle marge, of je nu eet of niet. Voel je je toch beroerd, dan is dat meestal wennen. Gebruik je medicatie of heb je diabetes, overleg dat dan wel met je huisarts voordat je gaat vasten.',array['fast_early','fast_mid']::text[],null,false,null,null),
('fys-a-06','fysiologie','Negeer je een hongergolf, dan zakt hij weg','Half elf, je maag knort, je denkt: nu moet ik iets. Doe eens niks. Ga door met waar je mee bezig was en verzet je aandacht. Grote kans dat het gevoel binnen een kwartier vanzelf minder wordt. Ghreline piekt en zakt weer, ook zonder eten. De honger die je nu voelt is niet de honger die je over een half uur voelt. Je hoeft er alleen even niet aan toe te geven, niet hem voor eeuwig weg te vechten.',array['fast_mid']::text[],null,true,'Doe twintig push-ups of een paar squats.',null),
('fys-a-07','fysiologie','Een lege maag is geen leeg lichaam','Dit is het belangrijkste onderscheid van de eerste uren. Een lege maag voelt als honger, maar het zegt niets over je energievoorraad. Je hebt brandstof opgeslagen in je lever en je vetweefsel, genoeg voor veel langer dan een ochtend. Het knorrende gevoel is een mechanisch en hormonaal signaal van een leeg spijsverteringskanaal, niet een melding dat de tank leeg is. Zodra je die twee uit elkaar houdt, wordt vasten een stuk rustiger.',array['fast_early','fast_mid']::text[],null,true,'Zet een kop zwarte koffie.',null),
('fys-a-08','fysiologie','Tien uur, maag rammelt, en toch energie','Je zit op je werk, het is tien uur, en je maag begint te rammelen. Tegelijk denk je helder na, je tikt door je mails, je bent niet slap. Dat is geen tegenstrijdigheid. Het rammelen komt van een leeg maagdarmkanaal dat samentrekt, niet van een gebrek aan brandstof. Je hersenen en spieren draaien gewoon door op wat je lever en je vet aanleveren. Het geluid is luider dan de boodschap. Er is niets aan de hand.',array['fast_mid']::text[],null,false,null,null),
('fys-a-09','fysiologie','De beste truc tegen een hongerpiek is beweging','Een hongerpiek in de ochtend gaat vaak sneller voorbij als je iets anders gaat doen. Sta op, loop een rondje, ga even naar buiten. Beweging verlegt je aandacht en de piek van ghreline zakt intussen vanzelf weg. Blijf je stilzitten en naar de klok staren, dan lijkt elk kwartier een uur. Het is geen wilskracht die je nodig hebt, maar een andere bezigheid tot de golf voorbij is.',array['fast_mid','fast_late']::text[],null,true,'Ga tien minuten naar buiten wandelen.',null),
('fys-a-10','fysiologie','Waarom het rammelt rond je vaste eetmomenten','Je lichaam is een gewoontedier. Eet je normaal om acht uur ''s ochtends, dan maakt je lichaam rond die tijd alvast ghreline aan, in verwachting van eten. Vandaar dat de honger vaak precies aanklopt op je oude ontbijttijd, en niet willekeurig. Het goede nieuws: dat patroon is aan te leren en af te leren. Sla je het ontbijt een tijdje over, dan worden die pieken op dat tijdstip vanzelf kleiner. Je lichaam verwacht dan niets meer.',array['fast_early','fast_mid']::text[],null,false,null,'waargenomen in onderzoek naar maaltijdgewoontes'),
('fys-a-11','fysiologie','Dat knorren betekent niet dat je verhongert','Dat borrelende, knorrende geluid in je buik heeft een naam en een functie. Als je maag en darmen een tijd leeg zijn, komt er een soort schoonmaakgolf op gang die restjes doorschuift. Dat maakt geluid. Het is een teken dat je spijsvertering leeg en aan het opruimen is, niet dat je lichaam in nood zit. Veel mannen horen dat geknor en denken meteen aan eten. Het is eerder een opgeruimd systeem dan een noodkreet.',array['fast_mid']::text[],null,false,null,null),
('fys-a-12','fysiologie','Is het honger of is het gewoonte?','Stel jezelf de vraag op het moment dat je iets wilt pakken: heb ik echt honger, of is het gewoon de tijd waarop ik altijd eet? Vaak is het dat tweede. Je hand gaat naar de kast omdat de klok dat zegt, niet omdat je lijf om brandstof vraagt. Echte honger na een paar uur bestaat, maar in de eerste uren van je vast is het meestal je routine die praat. Even stilstaan bij dat verschil scheelt een hoop onnodige happen.',array['fast_early','fast_mid']::text[],null,false,null,null),
('fys-a-13','fysiologie','Water vult je maag, letterlijk','De honger van de eerste uren zit vaak in je maag zelf, niet in een tekort verderop. Vul je die maag met een groot glas water, dan rekt de wand een beetje op en zakt het lege gevoel tijdelijk weg. Dat komt doordat reksensoren in je maagwand een signaal van volheid doorgeven. Het is tijdelijk, de honger kan terugkomen, maar het helpt je prima over een piek heen. Fysiologie die je gratis in de hand hebt.',array['fast_mid','fast_late']::text[],null,true,'Drink langzaam een groot glas water.',null),
('fys-a-14','fysiologie','In de eerste uren verteer je nog volop','Vasten begint niet op het moment dat je je vork neerlegt. De eerste uren is je lichaam nog volop bezig met verteren en opnemen: voedsel verlaat de maag, de dunne darm haalt er voedingsstoffen uit, insuline doet zijn werk. Pas als dat achter de rug is, ergens na een paar uur, zakt je lichaam in een rustiger ritme. Dat verklaart waarom je vlak na het eten geen honger hebt en die pas later opkomt. De vertering loopt gewoon nog.',array['fast_early']::text[],null,false,null,null),
('fys-a-15','fysiologie','Je hersenen krijgen gewoon brandstof','Je hersenen draaien in de eerste uren van je vast op glucose, en die blijft binnenkomen. Je lever geeft gedoseerd suiker af uit zijn voorraad, precies genoeg om je hoofd helder te houden. Daarom kun je prima een vergadering draaien of met je kinderen spelen op een lege maag. Het idee dat je zonder ontbijt niet kunt nadenken klopt voor de meeste gezonde mensen niet. De aanvoer stopt niet zodra de maag leeg is.',array['fast_mid']::text[],null,false,null,null),
('fys-a-16','fysiologie','De honger komt terug, en gaat opnieuw weg','Geef je niet toe aan de eerste hongergolf, dan kan er later een tweede komen. Ook die zakt weer. Wat veel mannen verrast in hun eerste vastdagen: de honger wordt niet gestaag erger tot je bezwijkt. Hij komt in vlagen, met rustige stukken ertussen. Vaak is de golf rond je oude etenstijd de heftigste, en daarna wordt het juist makkelijker in plaats van moeilijker. Dat patroon leren kennen maakt de eerste uren een stuk voorspelbaarder.',array['fast_mid','fast_late']::text[],null,false,null,null),
('fys-a-17','fysiologie','Juist nu, met die lege maag, gebeurt het','Dit ongemakkelijke moment met een knorrende maag is niet verloren tijd. Juist nu is je insuline laag en is je lichaam niet bezig met opslaan maar met huishouden. Je lever tapt van zijn voorraad, je spijsvertering rust. Het lege gevoel is precies het teken dat het werkt zoals bedoeld. Je hoeft er niets voor te doen behalve even niet eten. Zet iets in gang en laat je lichaam intussen zijn gang gaan.',array['fast_mid','fast_late']::text[],null,true,'Poets je tanden.',null),
('fys-b-01','fysiologie','De overstap naar vet begint','Ergens tussen uur veertien en zestien raakt je lever door zijn glycogeen heen. Vanaf dat moment schakelt je lichaam steeds meer over op vet als brandstof. Dat gaat niet met een klik, maar geleidelijk. De ene dag merk je er weinig van, de andere dag voel je het aan je energie. Wat je merkt hangt af van je vorige maaltijd, je slaap en hoeveel je beweegt. Verwacht geen wonder rond een vast uur. Het is een overgang, geen schakelaar.',array['fast_mid']::text[],null,false,null,null),
('fys-b-02','fysiologie','Wat ketonen eigenlijk zijn','Als je lichaam vet afbreekt, maakt de lever ketonen aan. Dat zijn kleine energiemoleculen die je hersenen en spieren kunnen gebruiken als glucose schaars wordt. Het is geen noodstof en geen gif. Het is een normale brandstof waar je lichaam op gebouwd is. Rond uur zestien tot twintig lopen ze langzaam op, bij de een sneller dan bij de ander. Je hoeft er niets voor te doen behalve niet eten. De rest gebeurt vanzelf.',array['fast_mid','fast_late']::text[],null,false,null,null),
('fys-b-03','fysiologie','De helderheid die vasters melden','Veel mensen zeggen dat ze rond uur zestien tot twintig helder in hun hoofd zitten. Rustiger, meer focus. Waarschijnlijk speelt noradrenaline daarin mee, plus het uitblijven van de dip na een grote maaltijd. Als constant effect is het niet hard bewezen, en niet iedereen ervaart het. Maar als jij het merkt: gebruik het. Plan je lastigste klus in dat raam. Werk je door dat ene ding heen waar je al dagen tegenaan hikt.',array['fast_late']::text[],null,true,'Pak nu de klus op die je steeds uitstelt.','de helderheid is subjectief en niet hard aangetoond bij mensen'),
('fys-b-04','fysiologie','Adrenaline houdt je scherp','Tijdens het vasten stijgen adrenaline en noradrenaline licht. Dat klinkt alarmerend, maar het is functioneel: het houdt je alert en helpt vet vrij te maken uit je voorraden. Het is ook de reden dat je je soms juist energieker voelt in plaats van slap. Bij sommige mensen geeft het lichte onrust of een sneller hart. Merk je dat het te veel wordt, dat je gejaagd of licht in je hoofd raakt, dan is minder streng vasten of overleg met je huisarts verstandig.',array['fast_mid','fast_late']::text[],null,false,null,null),
('fys-b-05','fysiologie','Groeihormoon: het eerlijke verhaal','Je hebt vast gelezen dat vasten groeihormoon flink verhoogt. Dat klopt in de metingen. Wat er meestal niet bij staat: verhoogd groeihormoon betekent niet automatisch meer spieren of vetverlies dat je op de weegschaal ziet. Het lijkt vooral een signaal dat je lichaam spiereiwit spaart terwijl er even geen voedsel binnenkomt. Nuttig, maar geen spierwonder. Laat je niet gek maken door koppen die suggereren dat je van vasten alleen al gespierder wordt.',array['any']::text[],null,false,null,'het verband met zichtbare spier- of vetresultaten is bij mensen niet hard aangetoond'),
('fys-b-06','fysiologie','Je spieren verdwijnen niet meteen','Een veelgehoorde angst: als ik niet eet, breekt mijn lichaam meteen spieren af. Zo werkt het niet. Je lichaam gebruikt eerst glycogeen, daarna steeds meer vet. Ketonen en een paar hormonale aanpassingen zorgen ervoor dat je spiereiwit grotendeels gespaard blijft tijdens een vast van een halve dag tot een dag. Voor de korte vensters waar we het hier over hebben, is spierverlies geen realistische zorg. Eet je genoeg eiwit in je venster en blijf je trainen, dan zit je goed.',array['any']::text[],null,false,null,null),
('fys-b-07','fysiologie','De tweede adem','Er is vaak een zwaar punt, ergens tussen uur veertien en achttien. Honger, een leeg gevoel, twijfel. En dan, als je erdoorheen zit, komt bij veel mensen een soort tweede adem. De honger zakt, je hoofd wordt rustiger, je vergeet bijna dat je niet gegeten hebt. Dat is deels de overgang naar vet en ketonen, deels gewoon dat de hongergolf voorbij is. Het punt: het zwaarste moment is meestal niet het einde, maar net daarvoor.',array['fast_late']::text[],null,true,'Zet een timer op dertig minuten en kijk of de golf zakt.',null),
('fys-b-08','fysiologie','Ketonen en je hersenen','Je hersenen draaien normaal op glucose, maar ze kunnen prima een flink deel van hun energie uit ketonen halen. Dat is precies waarom je niet suf tegen de vlakte gaat als je een dag niet eet. Het lichaam heeft dit systeem niet voor niets: onze voorouders aten ook niet elke drie uur. De overschakeling verklaart mogelijk het heldere gevoel dat sommigen melden. Suf hoef je je in elk geval niet te voelen.',array['fast_mid','fast_late']::text[],null,false,null,'een prestatievoordeel is bij mensen niet hard aangetoond'),
('fys-b-09','fysiologie','Het scenario rond uur zeventien','Half vijf in de middag. Je hebt sinds gisteravond niet gegeten, het venster gaat pas over een paar uur open. Je maag knort, je gedachten dwalen af naar de koelkast. Dit is vaak het zwaarste stuk. Belangrijk om te weten: op dit punt schakelt je lichaam net stevig over op vet. Wat voelt als ''ik red het niet'' is fysiologisch juist het kantelpunt. Drink wat, loop een rondje, en de kans is groot dat het over een halfuur draaglijker is.',array['fast_late']::text[],null,true,'Loop een blokje om en drink onderweg water.',null),
('fys-b-10','fysiologie','Waarom je verbranding niet instort','Mensen denken soms dat je stofwisseling meteen op slot gaat als je een maaltijd overslaat. Op de korte termijn gebeurt het tegenovergestelde: noradrenaline houdt je verbranding op peil of iets erboven tijdens een vast van een dag. Pas bij langdurig en fors te weinig eten over weken past je lichaam zich echt neerwaarts aan. Eén dag vasten zet je verbranding niet stil. Dat is een van de redenen dat korte vensters houdbaar zijn zonder dat je lichaam in de spaarstand schiet.',array['any']::text[],null,false,null,null),
('fys-b-11','fysiologie','Groeihormoon is geen spiergroei','Nog even over dat groeihormoon, want de verwarring zit diep. Verhoogd groeihormoon tijdens vasten is vooral een beschermingsmechanisme: het helpt je vet aanspreken en je spiereiwit sparen. Het is niet hetzelfde als de anabole opbouw die je van krachttraining en eiwit krijgt. Wie denkt dat hij door alleen te vasten spiermassa aanmaakt, komt bedrogen uit. Spieren bouw je in het venster, met training en genoeg eten. Vasten regelt eromheen, meer niet.',array['any']::text[],null,false,null,null),
('fys-b-12','fysiologie','Vetverbranding is een glijdende schaal','Het is verleidelijk om te denken: na zestien uur sta ik ''in de vetverbranding''. Zo binair is het niet. Je verbrandt altijd een mix van vet en koolhydraten. Naarmate de vast vordert, verschuift die mix richting vet. Er is geen deur die opengaat op een exact uur. Dat betekent ook dat een vast die net iets korter of langer is niet meteen alles verpest. De verschuiving is geleidelijk, en dat is juist prettig.',array['fast_mid','fast_late']::text[],null,false,null,null),
('fys-b-13','fysiologie','Is die helderheid echt?','Een eerlijke vraag om jezelf te stellen: dat heldere, rustige gevoel na uur zestien, is dat de ketonen of is het dat je even niet met eten bezig bent? Waarschijnlijk allebei. Voor de praktijk maakt het weinig uit. Als je merkt dat je in dat raam beter nadenkt en minder afgeleid bent, is dat bruikbaar, of de oorzaak nu hormonaal is of gewoon rust. Test het een week: leg je denkwerk in dat blok en kijk wat het doet.',array['fast_late']::text[],null,true,'Plan je moeilijkste taak in het heldere raam van vandaag.',null),
('fys-b-14','fysiologie','Ketonen meten hoeft niet','Je kunt ketonen meten met stripjes of een bloedmetertje. Leuk voor de cijferaars, maar nodig is het niet. De waarden schommelen door slaap, beweging en je laatste maaltijd, en een getal maakt je vast niet effectiever. Voor een drukke vader die gewoon een simpel ritme wil: laat de stripjes liggen. Het gaat om volhouden, niet om een meetwaarde optimaliseren. Ben je nieuwsgierig, prima, maar zie het als hobby, niet als noodzaak.',array['any']::text[],null,false,null,null),
('fys-b-15','fysiologie','Waarom je niet uitgehongerd bent','Na zestien of achttien uur zonder eten voelt honger soms als een noodsituatie. Fysiologisch ben je dat niet. Je hebt ruim voldoende vet als reserve, ketonen komen op gang, en je lichaam spaart bewust je spieren en organen. Echte uithongering speelt pas na veel langer zonder voedsel. Wat je voelt is een signaal, geen alarm dat er iets misgaat. Dat besef alleen al maakt het zwaarste uur vaak een stuk draaglijker.',array['fast_late']::text[],null,true,'Zeg tegen jezelf dat dit een signaal is en geen noodgeval, en drink een glas water.',null),
('fys-b-16','fysiologie','De dip vlak voor de ommekeer','Soms komt er een moment waarop het echt tegenzit. Je bent moe, chagrijnig, en de gedachte aan eten wordt luid. Dit is vaak precies het stuk vlak voordat de overgang naar vet zich stabiliseert. Je lichaam is aan het schakelen en dat kost even. Het is geen teken dat je faalt of dat vasten niets voor jou is. Het is een voorspelbaar dal. Doe iets fysieks, verleg je aandacht, en geef het een halfuur.',array['fast_late']::text[],null,true,'Doe twintig push-ups of loop een paar keer de trap op en neer.',null),
('fys-b-17','fysiologie','Als adrenaline je onrustig maakt','De keerzijde van die alertheid: bij sommige mensen geeft de lichte adrenalinestijging juist onrust. Je zit niet lekker in je vel, je bent kort aangebonden, je hart gaat sneller. Dat is meestal onschuldig en zakt weer. Wat helpt: iets van die energie kwijtraken met beweging in plaats van ertegen te vechten. Blijft het hardnekkig, of voel je je echt beroerd, dan is het slim minder streng te vasten of het met je huisarts te bespreken.',array['fast_mid','fast_late']::text[],null,true,'Ga naar buiten en wandel stevig door voor tien minuten.',null),
('fys-c-01','fysiologie','Wat autofagie wel en niet is','Autofagie is het opruimproces waarbij cellen versleten onderdelen afbreken en hergebruiken. Je leest online dat vasten dit aanzet en je lichaam zo "reset". Wees nuchter: het meeste bewijs komt uit muizen en kweekcellen. Bij mensen is het lastig te meten, en niemand weet precies vanaf welk uur of hoeveel het toeneemt. Het proces bestaat, dat klopt. Maar de exacte gezondheidswinst voor een mens die zestien uur vast, is niet hard aangetoond. Dat maakt vasten niet zinloos. Het betekent alleen dat je grote claims met een korrel zout neemt.',array['any']::text[],null,false,null,'vooral aangetoond in dierstudies'),
('fys-c-02','fysiologie','Er is geen magische autofagie-knop','"Na zestien uur schakelt autofagie aan." Die zin zie je overal. Het probleem: dat exacte getal komt niet uit degelijk mensenonderzoek. Autofagie is geen lichtknop die op een vast tijdstip klikt. Het loopt op de achtergrond en verandert geleidelijk, en de precieze timing bij mensen is grotendeels onbekend. Laat je vasten dus niet sturen door een stopwatch en een beloftevol getal. Het venster dat je kiest, kies je omdat het bij je dag past en vol te houden is. Niet omdat er op minuut nul iets magisch gebeurt.',array['fast_late']::text[],null,false,null,null),
('fys-c-03','fysiologie','Je insulinegevoeligheid verbetert traag','Regelmatig vasten kan je insulinegevoeligheid verbeteren, maar dat is een verhaal van weken, niet van één ochtend. Je lichaam gaat er over tijd beter mee om als je minder vaak op een dag je bloedsuiker laat pieken. Verwacht geen effect dat je op dag drie voelt. Dit is een langzame aanpassing die je niet merkt en niet kunt zien. Juist daarom is volhouden belangrijker dan één perfecte dag. De winst zit in het patroon over maanden, niet in de losse sessie van vandaag.',array['any']::text[],null,true,'Zet vandaag gewoon door tot je normale venster.','aangetoond in humane studies, effect verschilt per persoon'),
('fys-c-04','fysiologie','Metabole flexibiliteit, in gewone taal','Metabole flexibiliteit is het vermogen van je lichaam om vlot te wisselen tussen suiker en vet als brandstof. Wie de hele dag door eet, blijft vaak hangen op suiker en schakelt moeizaam over. Door regelmatig een tijd niet te eten, oefent je lichaam dat wisselen. Dat is geen wondermechanisme, maar een aannemelijk en gemeten effect. Het verklaart waarom de eerste weken zwaarder voelen: je lichaam is het schakelen ontwend. Na verloop van tijd gaat die overgang soepeler en voelt een gemiste maaltijd minder als een noodgeval.',array['any']::text[],null,true,'Drink een glas water en wacht rustig af.',null),
('fys-c-05','fysiologie','Ontstekingswaarden: het beeld is gemengd','Sommige studies laten zien dat vasten ontstekingsmarkers zoals CRP iets kan verlagen. Andere studies zien nauwelijks verschil. Het eerlijke antwoord is dus: mogelijk, maar niet gegarandeerd en niet groot. Veel van het effect dat wél gevonden wordt, hangt samen met het gewichtsverlies zelf, niet per se met het vasten los daarvan. Verwacht geen ontstekingsremmer op recept. Zie het als een mogelijk meevallertje bovenop de rest, niet als de reden om te beginnen.',array['any']::text[],null,false,null,'gemengde resultaten in humane studies'),
('fys-c-06','fysiologie','Waarom die claims zo groot klinken','Op sociale media wordt vasten verkocht als reset, detox en anti-verouderingskuur. Vraag je bij zo''n claim één ding af: is dit bij mensen aangetoond, of bij muizen en in een kweekbakje? Vaak is het dat laatste. De sprong van cel naar muis naar jarige vader is groot, en onderweg sneuvelt veel van de belofte. Dat betekent niet dat vasten niets doet. Het betekent dat de eerlijke effecten bescheidener zijn dan de koppen. Bescheiden en echt is beter dan groots en verzonnen.',array['any']::text[],null,false,null,null),
('fys-c-07','fysiologie','Niemand weet het precieze uur','Je wilt graag een getal: vanaf welk uur "telt" het? Bij autofagie bestaat dat getal voor mensen simpelweg niet betrouwbaar. Het meeste van wat je erover leest, is vertaald uit proefdieren, en muizen hebben een veel sneller metabolisme dan jij. Een muis van twaalf uur vasten is niet zomaar een mens van twaalf uur vasten. Laat die onzekerheid je niet frustreren. Het is juist een reden om te stoppen met minuten tellen en gewoon je ritme aan te houden.',array['fast_late']::text[],null,false,null,'extrapolatie uit dierstudies, timing bij mensen onbekend'),
('fys-c-08','fysiologie','Denk in weken, niet in dagen','De echte fysiologische aanpassingen, betere omgang met bloedsuiker en vlotter schakelen tussen brandstoffen, hebben tijd nodig. Je bouwt ze op over weken van herhaling, niet in één heldhaftige dag. Dat is lastig, want je wilt resultaat voelen. Maar veel van wat er verandert, merk je van binnen niet. Vergelijk het met conditie opbouwen: één keer hardlopen verandert weinig, twee maanden regelmaat verandert veel. Beoordeel je vasten dus niet op vandaag. Beoordeel het op het patroon van de afgelopen maand.',array['any']::text[],null,true,'Denk terug aan hoeveel dagen je deze maand al volhield.',null),
('fys-c-09','fysiologie','Een muis is geen vader van drie','Veel opwindende vastenresultaten komen uit muizenonderzoek. Handig voor de wetenschap, maar een muis leeft twee jaar, heeft een razendsnel metabolisme en vast in een lab zonder werk en kinderen. Wat bij zo''n dier na een korte vast gebeurt, kun je niet één op één op jezelf plakken. Als een artikel enthousiast is over een effect, check dan of het bij mensen is herhaald. Vaak is dat nog niet gebeurd, of veel zwakker. Gezond wantrouwen bespaart je teleurstelling en overdreven verwachtingen.',array['any']::text[],null,false,null,null),
('fys-c-10','fysiologie','Is het het vasten of het afvallen?','Als je insulinegevoeligheid verbetert tijdens een periode van vasten, is dat een goede zaak. Maar wetenschappers worstelen met een vraag: komt de winst door het vasten zelf, of gewoon doordat je minder eet en afvalt? In veel studies lijkt het vooral het gewichtsverlies te zijn. Vasten is dan een handige manier om minder te eten, niet per se een apart wondermechanisme. Voor jou in de praktijk maakt dat weinig uit. Voor de claims die je leest, maakt het alles uit.',array['any']::text[],null,false,null,'effect grotendeels toe te schrijven aan gewichtsverlies'),
('fys-c-11','fysiologie','Waarom honger na weken minder alarmerend voelt','In het begin voelt een gemiste maaltijd als een noodsituatie. Na een paar weken vasten voelt diezelfde honger vaak minder heftig. Een deel daarvan is gewenning in je hoofd. Maar een deel is fysiologisch: je lichaam schakelt makkelijker over op vet als brandstof en houdt je bloedsuiker stabieler tussen de maaltijden. Dat schakelen wordt beter met oefening. Het is een van de weinige effecten die redelijk goed onderbouwd is. Geef het dus tijd voordat je oordeelt of vasten bij je past.',array['fast_mid']::text[],null,true,'Herinner jezelf dat deze honger over een paar weken zachter voelt.',null),
('fys-c-12','fysiologie','Jaag niet op je bloedwaarden','Sommige mannen willen na een maand vasten meteen hun bloed laten prikken om te zien of hun ontstekingswaarden zijn gedaald. Begrijpelijk, maar riskant. Die waarden schommelen sterk door slaap, een verkoudheid, stress en je laatste training. Eén meting zegt weinig. En als het effect van vasten er al is, is het vaak klein. Je raakt sneller ontmoedigd door ruis dan dat je iets zinnigs leert. Wil je toch meten, doe het dan met je huisarts en over een langere periode, niet op basis van één prik.',array['any']::text[],null,false,null,null),
('fys-c-13','fysiologie','Autofagie is geen detox','"Autofagie ruimt gifstoffen op." Dat is een populaire draai die niet klopt. Autofagie recyclet versleten celonderdelen; het is huishouding op celniveau, geen ontgifting van je bloed. Je lever en nieren doen het echte filterwerk, elke dag, of je nu vast of niet. Wie vasten verkoopt als detoxkuur, verkoopt je een verzinsel. Het proces is interessant genoeg zonder die verpakking. Hou vast aan wat klopt: opruimen en hergebruiken binnen cellen, waarvan het nut bij de mens nog grotendeels onbewezen is.',array['any']::text[],null,false,null,'nut bij mensen grotendeels onbewezen'),
('fys-c-14','fysiologie','Wat redelijk vaststaat','Even de balans. Wat vasten aannemelijk doet bij mensen: het helpt je minder te eten, kan gewicht laten zakken, en oefent je lichaam in het schakelen tussen brandstoffen. Wat onzeker of overdreven is: dramatische autofagie-winst, forse ontstekingsremming, en anti-veroudering. Het eerste rijtje is genoeg reden om door te gaan. Het tweede rijtje is de reden om folders en influencers met wantrouwen te lezen. Als je weet wat echt is, verlies je geen energie aan beloftes die niet uitkomen.',array['any']::text[],null,false,null,null),
('fys-c-15','fysiologie','Stabielere bloedsuiker als stille winst','Een van de rustigere, beter onderbouwde effecten: bij regelmatig vasten worden je bloedsuikerpieken en -dalen over de dag vaak vlakker. Minder eetmomenten betekent minder pieken. Dat voel je soms als een gelijkmatiger energieniveau, zonder de scherpe inzinking na een lunch. Het is geen spectaculair effect en het gebeurt geleidelijk, maar het is er. Voor een drukke dag met kinderen is een stabieler energieverloop misschien waardevoller dan welke vage anti-verouderingsbelofte dan ook.',array['any']::text[],null,true,'Let vandaag eens op of je energie gelijkmatiger blijft dan vroeger.',null),
('fys-c-16','fysiologie','De belofte van langer leven','Vasten wordt geregeld gekoppeld aan langer leven. Die claim leunt zwaar op dieren: wormen, muizen, apen. Bij die soorten zijn er interessante signalen. Bij mensen kun je zoiets bijna niet netjes onderzoeken; je zou duizenden mensen tientallen jaren moeten volgen. Dat bewijs is er simpelweg nog niet. Iemand die stellig zegt dat vasten jou jaren erbij geeft, gaat verder dan de wetenschap toelaat. Kies vasten om redenen die je nu al kunt merken en controleren, niet om een belofte die niemand kan waarmaken.',array['any']::text[],null,false,null,'vooral dierstudies; langetermijnbewijs bij mensen ontbreekt'),
('fys-c-17','fysiologie','Waarom doe je het eigenlijk?','Een vraag om even bij stil te staan. Als morgen zou blijken dat autofagie bij mensen nauwelijks meetbaar is en de ontstekingswinst tegenvalt, zou je dan stoppen? Als je antwoord ja is, leun je te veel op onzekere beloftes. Als je antwoord nee is, dan doe je het om redenen die stevig staan: rust in je eetritme, minder gedachteloos snaaien, een simpele afspraak met jezelf. Bouw je motivatie op wat vaststaat en vandaag werkt. Dan raakt die niet aan het wankelen als een studie tegenvalt.',array['any']::text[],null,false,null,null),
('gezin-a-01','gezin','Je stoel blijft van jou','Vasten betekent niet dat je het ontbijt overslaat. Je slaat alleen het eten over. Dat verschil is groot. Kinderen registreren niet wat er op jouw bord ligt, wel of je stoel leeg is. Blijf dus gewoon aan tafel zitten, elke ochtend, op je vaste plek. Het ontbijtmoment is van het gezin, niet van jouw maag. Wie aanschuift hoort erbij, met of zonder bord.',array['fast_early','fast_mid']::text[],null,false,null,null),
('gezin-a-02','gezin','Koffie als vast anker','Een lege plek aan tafel voelt kaal, en lege handen ook. Zet daarom elke ochtend een mok zwarte koffie of thee op jouw plek. Het geeft je iets om vast te houden en iets om aan te nippen terwijl de rest eet. Na een paar weken is die mok jouw versie van het ontbijt. Vast ritueel, vaste plek, vast moment. Een nieuw patroon went sneller als er een herkenbaar anker in zit.',array['fast_early','fast_mid']::text[],null,true,'Zet een mok zwarte koffie en ga ermee aan tafel zitten.',null),
('gezin-a-03','gezin','Papa, waarom eet jij niet?','Die vraag komt een keer, meestal gewoon aan tafel. Houd het antwoord kort en feitelijk. Papa eet later, mijn eetmoment komt straks. Klaar. Kinderen accepteren simpele antwoorden; het zijn volwassenen die lange uitleg nodig hebben. Vermijd woorden als afvallen, dik of niet mogen. Je wilt niet dat je kind eten aan schuld koppelt. Later eten is geen straf en geen dieet, het is gewoon hoe papa het doet. Klinkt het antwoord rustig, dan is de vraag morgen alweer vergeten.',array['fast_early','fast_mid']::text[],null,false,null,null),
('gezin-a-04','gezin','Croissants op zaterdag: beslis vrijdag al','De geur van warme croissants om negen uur is een serieuze test. Beslis daarom vrijdagavond al wat je doet, niet zaterdagochtend met je neus boven de oven. Optie een: zaterdag is je ruime dag en je eet gewoon mee. Optie twee: je legt er twee opzij voor je eerste maaltijd. Beide keuzes zijn prima. Alleen ter plekke beslissen is een slecht plan, want tegen de geur van versgebakken deeg wint wilskracht zelden.',array['eat_close','fast_early','fast_mid']::text[],null,false,null,null),
('gezin-a-05','gezin','Twee handen vrij aan tafel','Wie niet eet, heeft als enige aan tafel twee handen vrij. Gebruik dat. Smeer boterhammen, schenk melk in, vang de beker op die omvalt, veeg de yoghurt van de vloer. Aan een ontbijttafel met jonge kinderen is er altijd werk. Het houdt je bezig, het ontlast je partner en het maakt je aanwezigheid concreet nuttig. Toeschouwer zijn is zwaar. Meedoen zonder bord is een stuk makkelijker.',array['fast_early','fast_mid']::text[],null,true,'Smeer de boterhammen voor de rest van de tafel.',null),
('gezin-a-06','gezin','Wat weet jij nog van je vaders ontbijt','Denk eens terug aan de ontbijten uit je eigen jeugd. Grote kans dat je nog weet of je vader erbij zat, of hij haast had, of hij iets vroeg. Wat hij at, weet je vrijwel zeker niet meer. Zo werkt het geheugen van jouw kinderen ook. Ze slaan op of jij er was en of je luisterde. Jouw lege bord haalt hun herinnering niet. Jouw afwezigheid wel.',array['fast_early','fast_mid']::text[],null,false,null,null),
('gezin-a-07','gezin','Zonder bord zitten went','De eerste ochtenden zonder eigen ontbijt voelen ongemakkelijk. Iedereen kauwt, jij zit daar. Dat is normaal en het gaat over. Gewoontes rond eten zitten diep; je hebt waarschijnlijk dertig jaar of langer vrijwel elke ochtend gegeten. Geef het een paar weken. Daarna is de mok koffie op jouw plek net zo vanzelfsprekend als het bord dat er eerst stond. Nieuw gedrag went, ook dit.',array['fast_early','fast_mid']::text[],null,false,null,null),
('gezin-a-08','gezin','Je ziet meer als je niet eet','Wie zelf zit te eten, is vooral met zijn eigen bord bezig. Wie niet eet, kijkt. Je ziet welk kind chagrijnig wakker is geworden, wie iets wil vertellen maar er niet tussen komt, wie zijn brood laat liggen. Het klinkt klein, maar veel vaders merken pas zonder eigen ontbijt hoeveel er aan zo''n tafel gebeurt. Gebruik dat. Stel de vraag die je anders niet had gesteld.',array['fast_early','fast_mid']::text[],null,false,null,null),
('gezin-a-09','gezin','Jouw vasten is niet hun vasten','Kinderen leren eetgedrag vooral door te kijken, en jij bent hun belangrijkste voorbeeld. Daarom twee regels. Een: jouw kinderen ontbijten gewoon, elke dag; een groeiend lijf is geen vastend lijf. Twee: praat aan tafel niet over calorieën, afvallen of slecht eten. Jij drinkt koffie en doet normaal, zij eten hun boterham. Zo ziet je kind een vader die rustig zijn eigen keuze maakt, zonder dat eten beladen wordt.',array['fast_early','fast_mid']::text[],null,false,null,'dat kinderen eetgedrag van ouders overnemen komt vooral uit observationeel onderzoek'),
('gezin-a-10','gezin','Het lange weekendontbijt','Doordeweeks duurt een ontbijt twintig minuten, in het weekend soms ruim een uur. Dat is lang zitten naast vers brood. Geef jezelf in het weekend daarom een taak buiten het stilzitten om. Loop eerst naar de bakker met een kind achterop, dek de tafel uitgebreid, pers verse jus voor de rest. Beweging en een rol maken dat uur draaglijker dan kijken en wachten. En het weekendontbijt wordt er voor het hele gezin beter van.',array['fast_early','fast_mid']::text[],null,false,null,null),
('gezin-a-11','gezin','Bewaar de croissant voor je venster','Een croissant is om tien uur lekker, maar om een uur ook. Valt het weekendontbijt je zwaar door wat er op tafel staat, leg dan bewust iets apart voor je eerste maaltijd. Zeg het hardop tegen jezelf of je partner: die is voor straks. Dat verandert de situatie van verbieden naar uitstellen, en uitstellen houden de meeste mensen veel langer vol. Vijf minuten in de oven en hij is weer als nieuw.',array['fast_early','fast_mid']::text[],null,false,null,null),
('gezin-a-12','gezin','Trek van kijken is geen lege tank','Zit je aan tafel en krijg je honger zodra de rest begint te eten? Dat klopt en het is verklaarbaar. Zien en ruiken van eten zet je spijsvertering alvast in de startblokken: meer speeksel, maagactiviteit, trek. Het is een normale voorbereidende reactie van je lichaam, geen teken dat je brandstof tekortkomt. Je reserves zijn ruim voldoende voor een ochtend. De trek zakt meestal weer zodra de borden van tafel zijn.',array['fast_early','fast_mid']::text[],null,true,'Schenk een grote mok thee of koffie in en drink die langzaam leeg.','deze zogeheten cefalische reactie op het zien en ruiken van eten is goed aangetoond bij mensen'),
('gezin-a-13','gezin','De rondvraag aan de ontbijttafel','Een concrete techniek voor wie het kijken naar etende gezinsleden zwaar valt: maak jezelf gespreksleider. Elke ochtend dezelfde vraag de tafel rond, bijvoorbeeld waar iedereen vandaag zin in heeft. Kinderen vinden zo''n vast rondje al snel het gewoonste van de wereld. Voor jou werkt het dubbel. Je aandacht gaat naar de antwoorden in plaats van naar de boterhammen, en je staat midden in het moment zonder een hap te nemen.',array['fast_early','fast_mid']::text[],null,true,'Vraag elk kind waar het vandaag het meest zin in heeft.',null),
('gezin-a-14','gezin','Maak er geen ding van','Je hoeft aan de ontbijttafel niet uit te leggen dat je vast. Niet elke dag, en eigenlijk nooit uit jezelf. Ga zitten, drink je koffie, praat mee. Kinderen nemen de sfeer over die jij uitstraalt: behandel jij het als normaal, dan is het normaal. Begin je elke ochtend over je schema, je uren en hoe zwaar het is, dan maak je van het gezinsmoment jouw project. Dat verdient het ontbijt niet.',array['fast_early','fast_mid']::text[],null,false,null,null),
('gezin-a-15','gezin','Eén zin met je partner vooraf','Bespreek het een keer met je partner voordat je begint: ik ontbijt voorlopig niet mee, maar ik zit er wel gewoon bij. Daarmee voorkom je dat de vraag waarom jij niet eet elke ochtend boven tafel hangt waar de kinderen bij zijn. Jullie geven hetzelfde rustige antwoord, klaar. Eén afspraak vooraf scheelt tien discussies aan tafel. En heeft je partner bezwaren, dan hoor je die liever op de bank dan tussen de boterhammen door.',array['any']::text[],null,false,null,null),
('gezin-b-01','gezin','De onzichtbare extra maaltijd','Een korstje hier, een halve boterham daar, twee happen pannenkoek bij het afruimen. Het voelt als niets, maar het telt op. Reken mee: een boterham met pindakaas is al snel 180 calorieën. Wie drie keer per dag iets van een kinderbord pakt, eet ongemerkt een extra maaltijd. Niet geregistreerd, niet geproefd, wel binnen. Juist omdat je het niet bewust neemt, corrigeer je er nergens voor. De eerste stap is simpel: weet dat het gebeurt.',array['any']::text[],null,false,null,null),
('gezin-b-02','gezin','Turf je happen, één ochtend lang','Hoe vaak gaat je hand richting je mond terwijl je smeert, opschept en afruimt? De meeste vaders gokken één of twee keer. Turf het eens een ochtend. Korstje, aangebeten boterham, restje yoghurt van de lepel, kruimel kaas van de snijplank. Vijf tot acht momenten is niet ongewoon. Je hoeft er die ochtend niets mee te doen. Alleen tellen. Wat je niet ziet, kun je niet veranderen; wat je turft, verandert vaak al vanzelf.',array['fast_early','fast_mid']::text[],null,false,null,null),
('gezin-b-03','gezin','Je lichaam is geen afvalbak','Weggooien voelt als verspilling. Dus eet je het restje op. Maar bekijk het nuchter: dat eten is al verloren op het moment dat je kind het laat liggen. Of het nu in de gft-bak verdwijnt of in jouw lichaam als overtollige energie — weg is het toch. Het enige verschil is waar het eindigt. Je lichaam gebruiken als vuilnisemmer lost geen voedselverspilling op. Kleinere porties opscheppen wel.',array['any']::text[],null,false,null,null),
('gezin-b-04','gezin','Korstjes zijn ook gewoon brood','Vier korstjes van twee boterhammen: dat is bijna een halve boterham. Doe dat bij ontbijt en lunch en je zit op een hele boterham per dag die je nooit hebt gezien als eten. Snijd de korstjes af boven de vuilnisbak, niet boven het aanrecht. Wat op het aanrecht ligt, gaat in je mond. Wat in de bak ligt, niet. De afstand tussen snijplank en prullenbak bepaalt meer dan je wilskracht.',array['fast_early','fast_mid']::text[],null,false,null,null),
('gezin-b-05','gezin','Pindakaas aan je vingers','Broodtrommels smeren om kwart over zeven. Pindakaas op het mes, hagelslag op het aanrecht, en je vingers gaan automatisch naar je mond. Dat is geen honger, dat is een gewoonte van dertig jaar oud. Doorbreek de keten fysiek: leg het mes direct in de vaatwasser, veeg de hagelslag met een vochtige doek in de bak en spoel je handen af. Klinkt overdreven. Werkt beter dan jezelf toespreken.',array['fast_early','fast_mid']::text[],null,false,null,null),
('gezin-b-06','gezin','Wat één korstje met je vast doet','Breekt één korstje je vast? Strikt genomen wel: ook een kleine hap zet je spijsvertering aan en laat je insuline licht stijgen. Hoe erg dat is, valt te nuanceren — van één korstje word je niet dik. Het echte probleem is het patroon. Wie zichzelf tien kleine uitzonderingen per dag toestaat, heeft geen venster meer maar een glijdende schaal. Behandel de vast daarom binair: dicht is dicht. Niet omdat één hap zoveel schade doet, maar omdat een heldere regel houdbaarder is dan onderhandelen per korstje.',array['any']::text[],null,false,null,'waar de grens van ''de vast breken'' precies ligt, is wetenschappelijk niet strak gedefinieerd'),
('gezin-b-07','gezin','Proeven tijdens het koken telt mee','Een lepel pastasaus, een stukje kaas bij het raspen, een frietje van het bakblik. Koken voor je gezin terwijl je venster dicht is, betekent een half uur lang kleine verleidingen. Twee opties. Eén: proef met een theelepel, beoordeel, en spuug uit als je streng wilt zijn — chef-koks doen het ook. Twee: laat je partner of je kind proeven. Een zesjarige vindt het prachtig om te mogen keuren of de saus goed is.',array['fast_early','fast_late']::text[],null,false,null,null),
('gezin-b-08','gezin','Bakje, deksel, koelkast','Sommige restjes zijn echt zonde. Een halve pannenkoek, een niet-aangeraakte boterham, het laatste stuk omelet. Daarvoor bestaat een simpele middenweg: bakje, deksel, koelkast. Eet het op als je venster open is, bij je lunch of als tussendoortje. Zo gooi je niets weg én blijft je vast intact. Je zult merken dat je de helft alsnog weggooit omdat je er om twaalf uur geen trek meer in hebt. Dat zegt iets over hoe graag je het om acht uur écht wilde.',array['fast_early','fast_mid']::text[],null,false,null,null),
('gezin-b-09','gezin','Eén vraag voor elke hap van het bord','Een koud korstje met een hap eruit. Drie slappe frietjes. Het aangelikte restje appelmoes. Stel jezelf één vraag voordat je het van het bord pakt: zou ik dit voor mezelf opscheppen als ik honger had? Vrijwel nooit. Je eet het niet omdat het lekker is of omdat je het nodig hebt, maar omdat het er ligt en jouw hand toevallig het bord vasthoudt. Eten dat de vraag niet doorstaat, gaat in de bak.',array['any']::text[],null,false,null,null),
('gezin-b-10','gezin','Die laatste boterham met kaas','Je kind vroeg om nóg een boterham, at er twee happen van en schoof het bord weg. Nu ligt daar een bijna hele boterham met kaas. Weggooien voelt fout — jouw ouders zeiden ook al dat je je bord leeg moest eten. Maar die regel was bedoeld voor het kind aan tafel, niet voor de vader die al veertig jaar prima gevoed is. Je mag een regel loslaten die niet meer voor jou geldt. De vuilnisbak is hier de volwassen keuze.',array['any']::text[],null,false,null,null),
('gezin-b-11','gezin','Ruim af met een als-dan-plan','Wilskracht op het moment zelf verliest het van dertig jaar gewoonte. Een vooraf gemaakte als-dan-afspraak werkt beter: als ik het bord van de kinderen oppak, dan schraap ik het meteen leeg in de gft-bak. Geen beslissing meer op het moment zelf; die is al genomen. Onderzoek naar zulke implementatie-intenties laat zien dat concrete als-dan-plannen gedrag aanzienlijk vaker doen slagen dan een algemeen voornemen als ''ik eet geen restjes meer''.',array['any']::text[],null,false,null,'implementatie-intenties (als-dan-plannen) zijn relatief goed onderzocht in de gedragspsychologie'),
('gezin-b-12','gezin','Kleinere porties, minder gevechten','Het beste restje is het restje dat niet bestaat. Kinderen laten structureel eten liggen als je te veel opschept. Geef de helft van wat je nu geeft en laat ze bijvragen — opscheppen kan altijd nog, terugleggen niet. Minder op het kinderbord betekent minder op jouw afruimstapel, en dus minder momenten waarop je iets moet weerstaan. Je verandert het patroon niet door harder te vechten, maar door het gevecht te verwijderen.',array['any']::text[],null,false,null,null),
('gezin-b-13','gezin','Tandpasta als slot op je mond','Poets je tanden vlak voordat je brood smeert, borden afruimt of gaat koken. Met een frisse muntsmaak is een koud korstje ineens een stuk minder aantrekkelijk. Het werkt op twee niveaus: eten smaakt slecht na tandpasta, en het poetsen zelf markeert een grens — mond dicht, klaar. Suikervrije kauwgom doet ongeveer hetzelfde op momenten dat de tandenborstel te veel gedoe is.',array['any']::text[],null,true,'Poets je tanden.',null),
('gezin-b-14','gezin','Je hand is sneller dan je hoofd','Sta je nu bij het aanrecht met een restje binnen handbereik? Dit moment duurt twintig seconden. De aandrang om die hap te nemen is een reflex, geen honger — je lichaam draait op dit moment prima op zijn eigen voorraad. Zet de tijd stil tussen prikkel en hap: loop weg van het aanrecht, ook al voelt dat onnozel. Afstand doodt de reflex. Wat je niet binnen armlengte hebt, eet je niet op.',array['fast_mid','fast_late']::text[],null,true,'Loop de keuken uit en drink een groot glas water.',null),
('gezin-b-15','gezin','Elke overgeslagen hap telt door','Elke keer dat je een automatische hap overslaat, wordt de gewoonte een fractie zwakker. Zo werkt een gewoontelus: zonder beloning dooft het patroon langzaam uit. De eerste week voelt elk korstje als een gevecht. Na een paar weken zie je het korstje liggen en gebeurt er niets meer in je hoofd. Dat punt komt echt, maar alleen als je de lus consequent onderbreekt. Vandaag overslaan is dus geen verloren moeite — het is de investering waarmee je dit gevecht straks niet meer hoeft te voeren.',array['any']::text[],null,true,'Gooi het restje nu weg en veeg het aanrecht schoon.','hoe snel een gewoonte uitdooft verschilt sterk per persoon; het vaak genoemde ''21 dagen'' is niet wetenschappelijk onderbouwd'),
('gezin-c-01','gezin','Op de verjaardag van je kind eet je taart','Je kind wordt vier. Er is taart om tien uur ''s ochtends. Eet een stuk mee. Een vader die aan de kant staat met een glas water terwijl iedereen viert, dat is het niet waard. Schuif je venster die dag naar voren of sla het vasten over. Eén dag verandert niets aan je resultaat op jaarbasis. Wat wel iets verandert: dat je erbij was, gewoon, met taart.',array['fast_early','fast_mid']::text[],null,false,null,null),
('gezin-c-02','gezin','Het korte antwoord op ''eet je niks''','Familiebezoek. Je schoonmoeder schuift de schaal je kant op. ''Eet je niks?'' Het beste antwoord is kort en zonder lading: ''Nee, straks. Lekker hoor.'' Klaar. Ga niet uitleggen, niet verdedigen, geen verhaal over insuline. Hoe meer woorden je gebruikt, hoe meer het een discussie wordt. Mensen accepteren een kort, rustig antwoord bijna altijd. Een lang antwoord nodigt uit tot tegenargumenten. En als je toch iets neemt omdat de sfeer dat vraagt: ook prima. Dat is geen nederlaag, dat is een keuze.',array['fast_mid','fast_late']::text[],null,false,null,null),
('gezin-c-03','gezin','Kiezen is iets anders dan breken','Er is een verschil tussen breken en kiezen. Wie op een feestje bezwijkt voor de derde plak cake, voelt dat als falen. Wie ''s ochtends al besluit ''vandaag vast ik niet, het is het feest van mijn dochter'', voelt niets van dat soort. Zelfde calorieën, totaal ander effect op je kop. Neem de beslissing dus vooraf, bewust, hardop desnoods. Een uitzondering die je zelf plant is geen zwakte. Het is precies hoe je dit jaren volhoudt in een leven met kinderen, verjaardagen en schoonfamilie.',array['any']::text[],null,false,null,null),
('gezin-c-04','gezin','Je kinderen luisteren mee','Kinderen kopiëren eetgedrag van hun ouders. Zeg daarom nooit waar ze bij zijn dat je ''niet mag eten'', dat je ''te dik'' bent of dat je ''zondigt''. Een kind van vijf onthoudt dat eten iets is met schuld en straf. Zeg in plaats daarvan: ''Ik eet straks, ik heb nu geen honger.'' Feitelijk, neutraal, klaar. Jouw vasten is een volwassen keuze met een volwassen reden. Houd het ook op dat niveau.',array['any']::text[],null,false,null,'dat kinderen eetgedrag en voedselopvattingen van ouders overnemen is goed onderzocht'),
('gezin-c-05','gezin','Vertel het je partner in twee zinnen','''Ik sla het ontbijt over en eet ''s avonds gewoon mee. Zeg het even als het je stoort.'' Meer hoeft het gesprek met je partner niet te zijn. Geen presentatie over ketonen, geen bekeringsdrang. Wat je partner vooral wil weten: eet je nog mee met het gezin, en word je er geen chagrijnige man van. Beantwoord die twee vragen met je gedrag, niet met woorden. Als het avondeten samen gewoon doorgaat en je humeur overeind blijft, is de discussie meestal binnen een week voorbij.',array['any']::text[],null,false,null,null),
('gezin-c-06','gezin','Het schoolfeestje om drie uur','Schoolplein, drie uur. Je zoon duwt een zelfgebakken cupcake in je handen, van juf gekregen, speciaal voor papa. Je hebt drie opties. Opeten en je venster een uur eerder openen. Bedanken en zeggen dat je hem na het eten neemt, thuis. Of hem opeten zonder er verder iets van te vinden. Alle drie zijn prima. De enige verkeerde optie is de cupcake weigeren op een manier die je zoon onthoudt. Zo''n moment weegt zwaarder dan één uur extra vasten ooit gaat opleveren.',array['fast_mid','fast_late']::text[],null,false,null,null),
('gezin-c-07','gezin','De rekensom van 52 zondagen','Stel: elke zondag croissants met het gezin, en je doet gewoon mee. Dat zijn 52 momenten per jaar buiten je schema. Klinkt veel. Maar tegenover die 52 staan ruim 300 dagen waarop je ritme gewoon staat. Consistentie op jaarbasis bepaalt je resultaat, niet de uitzondering op zondagochtend. Wie de zondag schrapt uit angst voor die croissant, houdt het drie weken vol en stopt dan helemaal. Wie de zondag inbouwt als vast gezinsmoment, houdt het jaren vol. Reken het zelf maar na.',array['fast_early','fast_mid']::text[],null,false,null,null),
('gezin-c-08','gezin','Een glas in je hand op het feestje','Op een verjaardag valt vooral op dat je niks vasthoudt. Niet dat je niks eet. Pak dus een glas bruiswater of zwarte koffie en houd het vast. Mensen registreren een vol glas als meedoen; niemand kijkt wat erin zit. Het geeft je handen iets te doen, het geeft je mond iets te doen, en het schrapt negentig procent van de vragen. Werkt op verjaardagen, recepties en bij de schoonfamilie op zondagmiddag.',array['fast_mid','fast_late']::text[],null,true,'Pak een glas bruiswater en houd het vast.',null),
('gezin-c-09','gezin','Overleeft je schema een kinderfeestje','Denk hier eens over na: als je schema geen verjaardagstaart, geen schoolfeestje en geen zondagse visite aankan, hoe lang gaat het dan mee in een gezin met jonge kinderen? Een regel die alleen werkt in een lege agenda is geen regel maar een tijdbom. Bouw de uitzonderingen dus in vanaf het begin. Feestdagen tellen niet mee. Verjaardagen van je kinderen tellen niet mee. Wat overblijft zijn gewone doordeweekse dagen, en dat zijn er meer dan genoeg om resultaat te halen.',array['any']::text[],null,false,null,null),
('gezin-c-10','gezin','Als je kind vraagt waarom papa niet eet','''Waarom eet jij geen taart, papa?'' Een kind van vier vraagt het zonder bijbedoeling, midden op het feestje, waar iedereen bij is. Houd het antwoord klein en waar: ''Ik heb nu geen honger, ik eet straks.'' Niet: ''Papa moet afvallen.'' Niet: ''Papa mag dat niet.'' Kinderen nemen de taal over waarmee thuis over eten wordt gepraat. Als eten bij jou klinkt als regels, verboden en lichaamsgewicht, wordt dat hun taal ook. Als het klinkt als honger en geen honger, blijft het gewoon eten.',array['fast_mid','fast_late']::text[],null,false,null,null),
('gezin-c-11','gezin','De familiebarbecue plan je in de auto','Een barbecue bij je schoonouders, familiebezoek dat de hele dag duurt, een verjaardag die uitloopt tot na het avondeten. Bepaal in de auto ernaartoe wat je doet. Optie één: je venster schuift op en je eet daar gewoon mee. Optie twee: vandaag geen vasten, morgen weer normaal. Wat niet werkt: ter plekke elke schaal die langskomt opnieuw beoordelen. Dat kost de hele middag energie en je verliest het toch. Eén beslissing vooraf is goedkoper dan veertig kleine beslissingen tussen de borrelnoten.',array['any']::text[],null,false,null,null),
('gezin-c-12','gezin','Je partner is geen dieetpolitie','Vraag je partner niet om je te controleren. ''Zeg jij er wat van als ik toch iets pak'' klinkt praktisch, maar maakt je partner verantwoordelijk voor jouw keuzes en zet spanning op elke maaltijd. Vertel wat je doet, vraag of het ergens botst met hoe jullie eten als gezin, en houd de uitvoering bij jezelf. Andersom geldt ook wat: als je partner een keer taart voor je meeneemt, is dat aardigheid, geen sabotage. Reageer dan ook zo.',array['any']::text[],null,false,null,null),
('gezin-c-13','gezin','De weegschaal na het feestje liegt','Sta je de ochtend na een verjaardag anderhalve kilo zwaarder op de weegschaal, dan is dat geen anderhalve kilo vet. Daarvoor zou je ruim tienduizend calorieën extra gegeten moeten hebben, en dat haalt zelfs de beste verjaardag niet. Het grootste deel is vocht en de inhoud van je maag en darmen. Binnen twee, drie dagen normaal ritme is het meeste weer weg. Trek dus geen conclusies uit die ene meting en ga niet extra streng compenseren. Gewoon je normale schema, vandaag.',array['fast_early']::text[],null,false,null,null),
('gezin-c-14','gezin','Als de taart rondgaat en jij vast','Je hebt vandaag bewust gekozen om te vasten, en nu gaat de taart rond. Dat knaagt. Bedenk dit: de taart is er over een uur nog, jouw keuze van vanochtend ook. Trek op een feestje komt vooral door zien en ruiken, niet door een lege maag. Loop dus even weg uit de kamer met het eten. Help met de kinderen, ruim glazen op, sta twee minuten buiten. Uit het zicht is uit de gedachten, zeker bij eten.',array['fast_mid','fast_late']::text[],null,true,'Loop twee minuten naar buiten, weg van het eten.',null),
('gezin-c-15','gezin','Word niet de man die over vasten begint','Niemand op een verjaardag zit te wachten op een verhandeling over eetvensters. Vertel er dus niet ongevraagd over, en houd het klein als iemand ernaar vraagt. Wie zijn vasten op elk feestje ter sprake brengt, maakt het groter dan het is, en dan wordt elke uitzondering meteen gezichtsverlies. Het is een eetritme, geen levensbeschouwing. De mannen die dit jaren volhouden zijn meestal de mannen van wie de omgeving het amper weet. Stille consistentie houdt langer stand dan luide overtuiging.',array['any']::text[],null,false,null,null),
('gezin-d-01','gezin','Slecht slapen zet je hongerhormonen op scherp','Na een korte nacht schuiven twee hormonen. Ghreline, dat honger geeft, stijgt. Leptine, dat verzadiging meldt, daalt. Het gevolg: je voelt je hongeriger dan je lichaam eigenlijk nodig heeft. Dat is geen gebrek aan wilskracht, dat is chemie. Handig om te weten op een ochtend na een gebroken nacht: de honger die je voelt is deels een slaaptekort-signaal, niet puur een brandstofvraag. Verwacht het, dan verrast het je minder.',array['fast_early','fast_mid']::text[],null,false,null,'aangetoond in slaapstudies bij mensen'),
('gezin-d-02','gezin','Als je kind om drie uur wakker stond','Half vier uit bed, een uur op de rand van het bed gezeten, om half zes weer wakker. Je begint de dag met een achterstand. De vast voelt dan zwaarder, en dat klopt ook. Verwacht niet dezelfde discipline als op een uitgeslapen dag. Je hoeft de dag niet af te blazen, maar wees mild in je verwachtingen. Plan minder, drink meer water, en beslis rond koffietijd hoe de rest eruitziet.',array['fast_early']::text[],null,false,null,null),
('gezin-d-03','gezin','Wanneer je de vast beter inkort','Een rotnacht is geen reden om meteen te stoppen, maar er zijn grenzen. Duizelig bij het opstaan, trillerige handen, niet helder kunnen nadenken terwijl je de kinderen naar school brengt: dan kort je het vasten in. Schuif je venster een paar uur naar voren en eet wat. Presteren met kleine kinderen in huis gaat voor een streng schema. Het is een dag. Morgen pak je de normale tijden weer op.',array['fast_early','fast_mid']::text[],null,true,'Eet nu iets kleins en start de vast morgen opnieuw.',null),
('gezin-d-04','gezin','Wat komt er voor het ontbijt in de plaats','Ontbijt was misschien je ankerpunt: de wekker, de boterham, de koffie, de deur uit. Valt het eten weg, dan valt er een gat in je ochtend. Vul dat bewust. Zet koffie of thee als vast ritueel. Smeer de broodtrommels van de kinderen. Ga vijf minuten naar buiten. Een routine zonder eten werkt alleen als er iets voor in de plaats komt, anders blijf je de hele ochtend aan de koelkast denken.',array['fast_early']::text[],null,false,null,null),
('gezin-d-05','gezin','Energie voor het stoeien aan het eind van de dag','De laatste uren van de vast vallen vaak samen met het drukste gezinsmoment: kinderen die willen spelen, stoeien, aandacht vragen. Je energie kan dan laag voelen. Twee dingen helpen. Drink een groot glas water met een snuf zout, want een deel van die matheid is vocht en zout, niet honger. En weet dat het tijdelijk is: zodra je venster opent, keert de energie terug. Een half uur stoeien red je bijna altijd.',array['fast_late']::text[],null,true,'Drink een groot glas water met een snuf zout.',null),
('gezin-d-06','gezin','Stem je venster af op het gezinsavondeten','Het grote voordeel van later eten: je eerste maaltijd kan samenvallen met het avondeten van het gezin. Iedereen aan tafel, jij eet mee, niemand die vraagt waarom je niets neemt. Kies je venster zo dat het opent rond of net voor het avondeten. Dan is je vast geen sociale last maar past hij precies in het ritme van het huis. Praktischer dan een venster dat midden op de werkdag opent en ''s avonds al dicht is.',array['eat_open','fast_late']::text[],null,false,null,null),
('gezin-d-07','gezin','Meer koffie na een slechte nacht: let op','De verleiding na een korte nacht is om de koffie te stapelen. Begrijpelijk, en zwarte koffie breekt je vast niet. Maar te veel cafeine op een moe lichaam kan je trillerig en gejaagd maken, en het verstoort de slaap van de komende nacht als je laat doordrinkt. Een of twee koppen in de ochtend, daarna water. Je wilt de volgende nacht niet ook slecht slapen omdat je om drie uur ''s middags nog een bak achteroversloeg.',array['fast_early','fast_mid']::text[],null,false,null,null),
('gezin-d-08','gezin','Wazig hoofd: slaap of vasten?','Voelt je hoofd wattig op een vastdag na een slechte nacht, dan is de vraag: komt dat door het vasten of door het slaaptekort? Meestal is het vooral het slaaptekort. Een uitgeslapen mens vast doorgaans een stuk makkelijker. Handig om te weten, want het betekent dat je de mist niet altijd met eten hoeft op te lossen. Water, daglicht en een korte wandeling doen op zo''n ochtend vaak meer dan een boterham.',array['fast_early','fast_mid']::text[],null,true,'Ga tien minuten naar buiten in het daglicht.',null),
('gezin-d-09','gezin','Zet de lat lager na een gebroken nacht','Op een dag na weinig slaap maak je meer fouten, heb je een korter lont en grijp je sneller naar snelle suikers. Dat is normaal. Stel je verwachtingen bij voordat de dag begint. Plan geen zware klussen of ingewikkelde beslissingen als het niet hoeft. Bescherm je vast door de dag simpel te houden. Wilskracht is een beperkte voorraad, en na een slechte nacht is die voorraad kleiner. Minder verleidingen op je pad betekent minder momenten waarop je bezwijkt.',array['fast_early','fast_mid']::text[],null,false,null,null),
('gezin-d-10','gezin','Eet met het gezin, niet erna','Een valkuil van het avondvenster: je eet met de kinderen mee, maar omdat je venster nog open is eet je later nog een keer als zij op bed liggen. Twee keer avondeten dus. Probeer je grootste maaltijd samen te laten vallen met het gezinsavondeten en sluit daarna af. Zo eet je genoeg, deel je het moment, en lig je niet met een volle maag in bed, wat je eigen slaap weer verstoort.',array['eat_mid','eat_close']::text[],null,false,null,null),
('gezin-d-11','gezin','De middagdip vangen zonder te breken','Rond drie, vier uur zakt je energie, zeker na een slechte nacht, en net dan komen de kinderen uit school met honger en drukte. Bereid je daarop voor. Een glas water, even zitten, tien rustige ademhalingen voordat je het huis in de chaos induikt. De dip is een golf: over twintig minuten voel je je alweer anders. Als je die twintig minuten overbrugt zonder de koektrommel open te trekken, ben je er doorheen.',array['fast_mid','fast_late']::text[],null,true,'Ga even zitten en adem tien keer rustig in en uit.',null),
('gezin-d-12','gezin','Het avondeten als ankerpunt van je dag','Als je vast eindigt bij het gezinsavondeten, krijgt dat moment extra gewicht. Je hebt de hele dag gewacht, en nu zit je samen aan tafel te eten. Voor veel vaders werkt dat beter dan losse maaltijden over de dag verspreid: een duidelijk moment om naar uit te kijken, samen met de mensen om wie het draait. Het maakt de vast niet alleen makkelijker vol te houden, het geeft de avond ook een vast ritme.',array['eat_open','fast_late']::text[],null,false,null,null),
('gezin-d-13','gezin','Niet eten om drie uur ''s nachts','Sta je toch op voor een huilend kind, dan is de verleiding klein maar reeel: een koekje, een restje, iets uit de kast omdat je toch wakker bent. Doe het niet. Nachtelijk eten breekt je vast en verstoort je systeem verder op een moment dat je juist weer wilt gaan slapen. Drink een glas water als je iets in je mond wilt. Ga terug naar bed. Je vast loopt gewoon door en ''s ochtends merk je er niets van.',array['fast_early']::text[],null,true,'Drink een glas water en ga terug naar bed.',null),
('gezin-d-14','gezin','Een week met slechte nachten vraagt souplesse','Jonge kinderen betekenen soms een reeks slechte nachten achter elkaar: tanden, oorontsteking, een griepje dat rondgaat. In zo''n periode stapelt slaaptekort zich op, en daarmee ook de honger en de matheid. Verwacht van jezelf niet dat je strak vast terwijl je halverwege de week op je tandvlees loopt. Kort in waar nodig, eet genoeg om overeind te blijven, en pak je normale tijden weer op zodra iedereen doorslaapt. Het schema staat in dienst van jouw leven, niet andersom.',array['any']::text[],null,false,null,null),
('gezin-d-15','gezin','Daglicht in de ochtend als vervanger van het ontbijt','Waar ontbijt vroeger je ochtend startte, kan daglicht die rol overnemen. Ga na het opstaan even naar buiten, ook al is het grijs. Ochtendlicht helpt je bioritme op gang en maakt je alerter, wat welkom is na een korte nacht. Bijkomend voordeel: het zet aan tot beter slapen de komende nacht. Breng je de kinderen lopend of op de fiets naar school, dan heb je dat moment al ingebouwd zonder er iets voor te hoeven plannen.',array['fast_early','fast_mid']::text[],null,false,null,null),
('mind-a-01','mindset','Honger is een golf, geen stijgende lijn','Honger voelt alsof het alleen maar erger wordt zolang je niet eet. Dat klopt niet. Hongerhormonen zoals ghreline stijgen rond je gewone eetmomenten en zakken daarna vanzelf weer, ook als je niets eet. Een hongergolf duurt meestal tien tot twintig minuten. Daarna ebt hij weg. Wie dat een paar keer bewust heeft meegemaakt, raakt niet meer van slag van een lege maag. Je hoeft de golf niet te stoppen. Hij stopt zelf.',array['fast_mid','fast_late']::text[],null,true,'Sta op en loop vijf minuten weg van je bureau of de keuken.','ghreline-schommelingen rond gewoonte-eetmomenten zijn goed gedocumenteerd bij mensen'),
('mind-a-02','mindset','Honger of trek: de boterhamtest','Twijfel je of je echt honger hebt? Stel jezelf één vraag: zou ik nu een gewone boterham met kaas eten? Is het antwoord ja, dan is het waarschijnlijk honger. Denk je meteen aan chips, koek of iets anders specifieks, dan is het trek. Honger is niet kieskeurig, trek wel. Trek verdwijnt zodra je aandacht ergens anders heen gaat. Honger komt terug, maar ook die kun je prima even laten wachten.',array['any']::text[],null,false,null,null),
('mind-a-03','mindset','De twintig-minuten-regel','Maak een simpele afspraak met jezelf: als de honger toeslaat, beslis je twintig minuten lang niets. Niet eten, niet piekeren, gewoon verder met waar je mee bezig was. Na twintig minuten kijk je opnieuw. Meestal is de golf dan gezakt en snap je niet meer waarom het zo urgent voelde. Is de honger er nog steeds en net zo sterk, dan weet je dat het echt is. Ook dan hoef je niets, maar dan neem je tenminste een bewuste beslissing.',array['fast_mid','fast_late']::text[],null,true,'Zet een timer op twintig minuten.',null),
('mind-a-04','mindset','Klokhonger is aangeleerd','Je krijgt honger om half één omdat je al jaren om half één luncht, niet omdat je lichaam op dat moment iets tekortkomt. Dat heet conditionering. Je lijf heeft geleerd wanneer er eten aankomt en bereidt zich daarop voor, compleet met knorrende maag en hongergevoel. Het goede nieuws: wat aangeleerd is, kan ook afgeleerd worden. Verschuif je je eetmomenten, dan schuift de klokhonger binnen een week of twee gewoon mee.',array['fast_mid']::text[],null,false,null,'aangeleerde honger rond vaste eetmomenten is aangetoond bij mensen'),
('mind-a-05','mindset','Avondtrek is meestal verveling','De kinderen liggen in bed. Je zakt op de bank en binnen tien minuten sta je bij de keukenkast. Herkenbaar. Vraag je op dat moment af: heb ik honger, of is dit het eerste rustige moment van de dag en zoek ik iets om te doen? Avondeten na het avondeten is zelden honger. Het is ontspanning, beloning of iets voor de handen. Verveling verdwijnt niet door te eten. Die verdwijnt door iets anders te gaan doen.',array['eat_close','fast_early']::text[],null,true,'Pak een klusje van vijf minuten: afwas, speelgoed opruimen, tas voor morgen klaarzetten.',null),
('mind-a-06','mindset','De eerste twee weken kalibreert je systeem','Reken erop dat de eerste een tot twee weken het zwaarst zijn. Je hongersignalen staan nog afgesteld op je oude eetritme en melden zich braaf op de oude tijden. Dat is geen teken dat vasten niet bij je past. Zie het als een verhuizing: je lichaam moet de nieuwe tijden nog leren. Bij de meeste mensen worden de hongergolven na ongeveer twee weken merkbaar milder en verschijnen ze rond de nieuwe eetmomenten. Trek dus geen conclusies in week één.',array['any']::text[],null,false,null,'onderzoek bij mensen laat zien dat hongersignalen zich binnen dagen tot weken aanpassen aan een nieuw eetpatroon'),
('mind-a-07','mindset','Zit de golf uit, vecht er niet tegen','Tegen honger vechten werkt averechts. Hoe harder je probeert er niet aan te denken, hoe groter het wordt. Doe het omgekeerde: bekijk het gevoel van een afstand. Waar zit het precies, in je maag of in je hoofd? Hoe sterk is het, op een schaal van één tot tien? Wordt het sterker of zwakker? Wie honger observeert in plaats van bevecht, merkt dat het gevoel beweegt en vanzelf afneemt. Je hoeft niets te winnen. Je hoeft alleen te wachten.',array['fast_mid','fast_late']::text[],null,true,'Geef je honger een cijfer van één tot tien en check over een kwartier opnieuw.',null),
('mind-a-08','mindset','Honger is een melding, geen alarm','Je lichaam stuurt een bericht: er mag eten aankomen. Meer is het niet. Voor een gezonde volwassene is een paar uur zonder eten geen enkel probleem. Toch reageren we vaak alsof er iets mis is en er meteen ingegrepen moet worden. Die reflex is aangeleerd, niet noodzakelijk. Een melding mag je ook gewoon lezen en wegklikken. Gebruik je medicijnen of heb je diabetes, overleg dan eerst met je huisarts voordat je maaltijden overslaat.',array['fast_mid','fast_late']::text[],null,false,null,null),
('mind-a-09','mindset','Dorst vermomt zich als honger','De signalen voor honger en dorst lijken op elkaar en worden makkelijk verward, zeker op een drukke dag waarop je te weinig drinkt. Voordat je een hongergevoel serieus neemt, is er een simpele check: drink een groot glas water en wacht tien minuten. Verdwijnt het gevoel, dan was het dorst. Blijft het, dan weet je meer. Kost niets en werkt verrassend vaak.',array['fast_early','fast_mid','fast_late']::text[],null,true,'Drink een groot glas water en wacht tien minuten.',null),
('mind-a-10','mindset','Wanneer had je voor het laatst echt honger','Denk daar eens serieus over na. Grote kans dat het jaren geleden is. Wat we dagelijks honger noemen is meestal trek, gewoonte of de klok. Echte honger, het gevoel na een hele dag zonder eten, kennen de meeste Nederlanders alleen van horen zeggen. Dat besef relativeert. De golf die je nu voelt is geen schaarste. Het is je oude ritme dat aan de deur klopt. Je hoeft niet open te doen.',array['fast_mid']::text[],null,false,null,null),
('mind-a-11','mindset','Drukte is je bondgenoot','Vrijdagochtend, volle agenda, twee overleggen achter elkaar. Om elf uur voelde je een stevige hongergolf opkomen. Om half twaalf ben je hem compleet vergeten, want je was ergens mee bezig. Dat zegt iets. Echte nood laat zich niet wegdrukken door een overleg. Honger die verdwijnt zodra je afgeleid bent, was geen noodsituatie. Gebruik dat mechanisme actief: plan je drukste taken in de uren waarin de golven meestal komen.',array['fast_mid']::text[],null,true,'Ga tien minuten naar buiten of begin aan de taak die je al dagen uitstelt.',null),
('mind-a-12','mindset','Trek op commando: de macht van de prikkel','Je loopt langs de bakker en hebt ineens honger. Vijf minuten eerder was er niets aan de hand. Dat is geen honger, dat is een reactie op een prikkel: een geur, een reclame, een collega die een broodje pakt. Prikkeltrek voelt urgent maar heeft een korte houdbaarheid. Loop door, en binnen een paar minuten is het weg. Echte honger heeft geen aanleiding van buiten nodig en komt terug, ook zonder bakker in de buurt.',array['any']::text[],null,false,null,null),
('mind-a-13','mindset','Honger stapelt niet op','Om tien uur voel je al honger en denk je: als het nu al zo is, hoe moet dat om vier uur? Die rekensom klopt niet. Honger is geen emmer die volloopt. Na een golf volgt een rustige periode, en veel mensen vinden de vroege middag juist makkelijker dan het einde van de ochtend. De angst voor de honger van straks is bijna altijd groter dan de honger van straks zelf. Je hoeft alleen deze golf uit te zitten, niet alle golven tegelijk.',array['fast_early','fast_mid']::text[],null,true,'Poets je tanden.',null),
('mind-a-14','mindset','Schrijf twee weken je golven op','Zet de komende twee weken een korte notitie in je telefoon, elke keer als een hongergolf komt: tijdstip en een cijfer voor de sterkte. Kost tien seconden. Na twee weken zie je twee dingen. De golven komen op voorspelbare momenten, meestal je oude eetmomenten. En ze worden week op week zwakker en schuiven op richting je nieuwe eetvenster. Dat overzicht maakt van honger iets meetbaars in plaats van iets bedreigends. Meten werkt beter dan hopen.',array['any']::text[],null,false,null,null),
('mind-b-01','mindset','Eén dag is drie procent van je maand','Reken het eens uit. Een maand heeft dertig dagen. Eén gemiste vastendag is ruim drie procent. Je lichaam reageert op wat je gemiddeld doet, niet op de uitzondering. Wie zesentwintig van de dertig dagen zijn venster haalt, zit op bijna negentig procent. Dat is waar het resultaat vandaan komt. Geen enkele meetbare uitkomst — gewicht, tailleomtrek, energie — hangt af van die ene dag. Noteer hem en ga door.',array['any']::text[],null,false,null,null),
('mind-b-02','mindset','Alles-of-nietsdenken is de echte valkuil','Uit onderzoek naar terugval bij gedragsverandering komt een bekend patroon: wie één keer uitglijdt, denkt al snel dat alles verpest is, en geeft daarom helemaal op. Niet de misstap zelf richt de schade aan, maar de conclusie die je eraan verbindt. Een roker die na het stoppen één sigaret rookt, hoeft niet het hele pakje op. Zo werkt het hier ook. Eén gebroken vast is één gebroken vast. De rest van de week bestaat nog gewoon.',array['eat_open','eat_mid']::text[],null,false,null,'patroon beschreven in terugvalonderzoek (abstinence violation effect)'),
('mind-b-03','mindset','De druk mag eraf','Stel dat je nu breekt. Wat gebeurt er dan echt? Niets meetbaars. Je week staat nog, je maand staat nog. Vreemd genoeg maakt dat besef het volhouden makkelijker: je vast niet omdat het moet, maar omdat je het af wilt maken. Dwang maakt de laatste uren zwaarder dan ze zijn. Haal de druk eraf en voel dan nog eens hoe zwaar het eigenlijk is.',array['fast_mid','fast_late']::text[],null,true,'Drink een groot glas water en beslis daarna opnieuw.',null),
('mind-b-04','mindset','Geen strafdienst na een misser','Gisteren ging het mis en vandaag wil je het goedmaken: langer vasten, de lunch schrappen, extra streng zijn. Doe dat niet. Compensatie maakt van een schema een strafsysteem, en strafsystemen houdt niemand jaren vol. Bovendien vergroot extra streng vasten na een misser de kans op de volgende misser. Vandaag gewoon je normale venster. Zelfde tijden als altijd. De misser is daarmee afgehandeld — er hoeft niets terugbetaald te worden.',array['fast_early','fast_mid']::text[],null,false,null,null),
('mind-b-05','mindset','Een streak is een teller, geen resultaat','Apps zijn dol op streaks. Drieënveertig dagen op rij — en dan breekt hij, en voelt het alsof alles weg is. Maar de teller staat in je telefoon, niet in je lijf. Je stofwisseling, je gewicht, je conditie: die zijn na dag drieënveertig niet ineens terug bij nul. Gebruik een streak als speelse motivatie zolang het werkt. Zodra een gebroken teller zwaarder weegt dan een gebroken dag, klopt de volgorde niet meer.',array['any']::text[],null,false,null,null),
('mind-b-06','mindset','Drie vragen, twee minuten, geen vonnis','Ging het mis? Doe kort onderzoek, geen rechtszaak. Drie vragen: wat gebeurde er vlak voor het moment, hoe had je geslapen, wat was er anders dan normaal? Vaak vind je iets praktisch — een vergadering door de lunch, een korte nacht, snacks in het zicht. Dat is bruikbaar. ''Ik heb geen discipline'' is dat niet: het verklaart niets en het verandert niets. Feiten verzamelen mag twee minuten duren. Daarna is het klaar.',array['eat_mid','eat_close']::text[],null,false,null,null),
('mind-b-07','mindset','Veertien uur telt ook','Je haalt de zestien uur vandaag misschien niet. Dan is veertien uur geen mislukking, maar een kortere vast. Alles-of-nietsdenken zegt: zestien of niks. Je lichaam kent die grens niet; het effect bouwt geleidelijk op en er gebeurt niets magisch op precies zestien uur. Elk uur telt gewoon mee. Wie vandaag om praktische redenen eerder eet, heeft niet gefaald maar ingekort. Dat onderscheid scheelt veel in hoe morgen voelt.',array['fast_late']::text[],null,true,'Ga tien minuten naar buiten.',null),
('mind-b-08','mindset','Nooit twee keer op rij','Eén regel voorkomt dat een incident een patroon wordt: mis nooit twee dagen achter elkaar. Eén gemiste dag is ruis. Twee is het begin van een nieuwe gewoonte — de verkeerde. De regel is prettig concreet: je hoeft gisteren niet goed te maken en je hoeft niet perfect te zijn, je hoeft alleen vandaag weer normaal te doen. Dat is een lage lat, en precies daarom werkt hij ook op drukke dagen met kinderen.',array['fast_early','fast_mid']::text[],null,false,null,null),
('mind-b-09','mindset','Wat zou je tegen een vriend zeggen','Een vriend vertelt dat hij gisteren zijn vast heeft gebroken omdat het een rotdag was met de kinderen. Zeg je dan dat hij een slappeling is en dat het nooit wat wordt? Waarschijnlijk zeg je: joh, één dag, morgen gewoon weer door. Let eens op het verschil met wat je tegen jezelf zegt. Mensen die zichzelf na een misstap normaal toespreken, houden gedragsverandering beter vol dan mensen die zichzelf afbranden.',array['eat_mid','eat_close']::text[],null,false,null,'klein aantal studies naar zelfcompassie en gedragsverandering'),
('mind-b-10','mindset','Breken of sneuvelen','Ga je eraan toegeven? Dat kan gebeuren. Maar er is verschil tussen breken en sneuvelen. Sneuvelen is staand bij het aanrecht haastig iets naar binnen werken en je meteen rot voelen. Breken is een besluit: bord pakken, aan tafel, rustig eten, klaar. Dezelfde calorieën, een totaal ander gevoel erna — en een veel kleinere kans dat de rest van de dag ontspoort.',array['fast_late']::text[],null,true,'Pak een bord en ga aan tafel zitten.',null),
('mind-b-11','mindset','De dag is niet toch al verpest','Om tien uur ging het mis: vlaai bij het werkoverleg. De verleiding is nu te denken dat de dag toch al verpest is, dus dat de rest ook niet meer uitmaakt. Dat is de echte schadepost. Niet dat ene stuk vlaai — dat zijn een paar honderd calorieën — maar de vrijbrief die je jezelf daarna geeft. Behandel de misser als afgerond: het is gebeurd, het telt, en vanaf nu loopt de dag gewoon weer volgens plan.',array['fast_mid','eat_open']::text[],null,false,null,null),
('mind-b-12','mindset','Plan voor negentig procent','Wie een jaar lang vast, mist dagen. Vakanties, verjaardagen, zieke kinderen, nachten van drie uur slaap. Reken daar vooraf op. Een schema dat alleen werkt bij honderd procent uitvoering is geen schema maar een gok. Mik op negen van de tien dagen en je hebt ruimte voor het echte leven, zonder dat elke afwijking als falen voelt. Perfectionisme is hier geen hoge standaard — het is de snelste route naar helemaal stoppen.',array['any']::text[],null,false,null,null),
('mind-b-13','mindset','Je lichaam rekent niet af met gisteren','Misschien ging het gisteren mis en voelt vandaag daardoor extra zwaar, alsof je iets moet bewijzen. Je lichaam doet niet aan bewijzen. Het reageert op wat er nu gebeurt: je eet niet, dus het schakelt over op zijn voorraden, precies zoals anders. Gisteren is fysiologisch afgesloten. De enige plek waar die dag nog bestaat, is in je hoofd. Laat hem daar niet zwaarder wegen dan hij in je lijf doet: niets.',array['fast_mid','fast_late']::text[],null,true,'Doe twintig push-ups.',null),
('mind-b-14','mindset','Over vijf jaar weet niemand het meer','Op welke dinsdag in maart je je vast brak, weet over vijf jaar niemand meer — jijzelf ook niet. Wat je dan wel merkt, is wat je in die vijf jaar gemiddeld deed. Je doet dit niet voor een perfecte week, maar voor gezondheid op de schaal van jaren, ook om er straks fit bij te lopen voor je kinderen. Weeg een gebroken dag op die schaal. Hij weegt vrijwel niets.',array['eat_mid','eat_close']::text[],null,false,null,null),
('mind-c-01','mindset','Eén regel is makkelijker dan honderd keuzes','Wilskracht is onbetrouwbaar. De ene dag heb je genoeg, de andere dag ben je om zeven uur ''s avonds al leeg. Een vaste regel werkt anders: die vraagt geen energie. Je onderhandelt niet meer over elk los moment, want de uitkomst staat vast. ''Ik eet om twaalf uur'' is geen besluit dat je elke ochtend opnieuw neemt, maar één besluit dat je één keer nam. Dat is het verschil tussen iets volhouden en er elke dag mee vechten.',array['fast_mid','fast_late']::text[],null,false,null,null),
('mind-c-02','mindset','Half tien ''s avonds is het gevaarlijkste moment','De kinderen liggen in bed. Je zit eindelijk op de bank en je hand wil richting de kast. Geen toeval: aan het einde van zo''n dag ben je moe, en moe maakt elke verleiding zwaarder. Precies daarom werkt een vaste eindtijd. De keuken is dicht, klaar. Je hoeft nu niet sterk te zijn; je hoeft alleen niets te doen.',array['eat_close','fast_early']::text[],null,true,'Drink een groot glas water.',null),
('mind-c-03','mindset','Wat niet in huis is, eet je niet','Je kunt elke avond vechten tegen de zak chips in de kast, of je kunt hem één keer niet kopen. De supermarkt is de plek waar je de strijd van half tien ''s avonds wint of verliest. Doe boodschappen met een lijst en niet met honger, en laat de dingen liggen die je ''s avonds naar binnen trekken. Helemaal leeg wordt het huis niet met kleine kinderen; leg hun koeken dan op één vaste plek, uit het zicht. Omgeving verslaat wilskracht, vrijwel altijd.',array['any']::text[],null,false,null,null),
('mind-c-04','mindset','Koppel het aan wat je al doet','Een nieuwe gewoonte houdt beter stand als hij vasthangt aan iets dat je al doet. Kies ankers die er al zijn: als de kinderen naar bed zijn gebracht, gaat de keuken dicht. Je eetvenster opent op het moment dat je lunchpauze begint. Zo hoef je niets te onthouden en niets te beslissen. Het ritme van je dag draagt de gewoonte, in plaats van je geheugen of je discipline.',array['any']::text[],null,false,null,null),
('mind-c-05','mindset','De eerste drie weken zijn het zwaarst','Dat het nu zwaar voelt, zegt weinig over hoe het over een maand voelt. Je lijf is jarenlang getraind om op vaste momenten eten te verwachten, en die verwachting verdwijnt niet in drie dagen. De meeste mensen merken dat de ochtendhonger na twee tot drie weken duidelijk afneemt. Niet omdat ze sterker zijn geworden, maar omdat het nieuwe ritme normaal is geworden. Hou de eerste drie weken vol op de regel, niet op gevoel.',array['fast_mid','fast_late']::text[],null,true,'Streep vandaag af op een kalender.','afname van honger bij vaste eettijden is in kleine studies bij mensen beschreven'),
('mind-c-06','mindset','Je bent geen man op dieet','Er is een verschil tussen ''ik mag niet eten'' en ''ik eet ''s ochtends niet''. Het eerste is een verbod dat je elke dag opnieuw moet handhaven. Het tweede is gewoon wie je bent, zoals je ook geen sigaretten rookt of geen bier drinkt bij het ontbijt. Een dieet is iets tijdelijks waar je vanaf wilt. Een identiteit hoef je niet vol te houden; die ben je.',array['fast_early','fast_mid']::text[],null,true,'Zeg één keer hardop: ik eet ''s ochtends niet.',null),
('mind-c-07','mindset','Kwart over tien bij de koffieautomaat','Iemand zet iets lekkers neer bij de koffieautomaat, of je loopt langs de kantine. Zonder regel begint nu een gesprek in je hoofd: één keer kan wel, het is maar klein, vanmiddag eet ik dan wat minder. Dat gesprek kost energie en je verliest het vaak. Met een vaste regel is er geen gesprek. Je eet om twaalf uur. De vraag is al beantwoord voordat hij gesteld werd.',array['fast_mid']::text[],null,false,null,null),
('mind-c-08','mindset','Hoeveel eetbeslissingen nam je gisteren?','Wel of geen ontbijt, iets bij de koffie, iets uit de kast na het avondeten, het bakje op de bank. Zonder vaste regel neem je tientallen kleine eetbeslissingen per dag, en elke beslissing is een kans om te verliezen. Tel ze morgen eens. Een eetvenster brengt dat aantal terug naar bijna nul: binnen het venster eet je, erbuiten niet. Minder beslissingen is minder verliesmomenten. Zo simpel is de rekensom.',array['any']::text[],null,false,null,null),
('mind-c-09','mindset','Saai is precies wat je wilt','Een schema dat elke dag schuift, is elke dag een nieuwe beslissing. Vandaag om elf uur eten, morgen om één uur, in het weekend maar zien. Dat voelt flexibel, maar het houdt het onderhandelen in stand. Vaste tijden maken het saai, en saai is hier een compliment: geen afweging, geen uitzondering, geen gedoe. Kies tijden die op werkdagen én in het weekend haalbaar zijn, en laat ze daarna met rust.',array['any']::text[],null,false,null,null),
('mind-c-10','mindset','Motivatie is geen plan','Je poetst je tanden ook op dagen dat je er geen zin in hebt. Niet door motivatie, maar omdat het geen vraag meer is. Zo werkt het hier ook. Motivatie is er in week één vanzelf en in week drie vaak niet meer; dat is normaal en zegt niets over jou. Bouw dus niet op zin, maar op ritme. De dagen dat je er niets bij voelt en het toch gewoon doet, zijn de dagen die tellen.',array['any']::text[],null,true,'Zet zwarte koffie.',null),
('mind-c-11','mindset','Elke keer dat je volhoudt, wordt het lichter','Dit zware moment is niet alleen iets om doorheen te komen. Het is precies het moment waarop de gewoonte gebouwd wordt. Elke keer dat je je aan de regel houdt terwijl het moeilijk is, bevestig je voor jezelf dat die regel echt vaststaat. De volgende keer is daardoor iets minder zwaar. Je bent nu niet aan het overleven; je bent aan het trainen.',array['fast_mid','fast_late']::text[],null,true,'Ga tien minuten naar buiten.',null),
('mind-c-12','mindset','Maak de goede keuze de makkelijke keuze','Gewoontes volgen de weg van de minste weerstand. Gebruik dat. Zet ''s avonds de waterkoker klaar, leg een gevulde bidon in de koelkast en zorg dat je eerste maaltijd geen denkwerk vraagt. Hoe minder stappen tussen jou en de goede keuze, hoe vaker die keuze wint. Andersom geldt hetzelfde: hoe meer stappen tussen jou en de snacks, hoe minder vaak je ze eet. Bovenste plank, achterin, in een dichte doos.',array['eat_close','fast_early']::text[],null,false,null,null),
('mind-c-13','mindset','Beoordeel het niet in week één','Hoe lang duurt het voordat gedrag automatisch wordt? In een bekende studie was het gemiddelde ruim twee maanden, met grote verschillen tussen mensen: van een paar weken tot veel langer. Wat dat betekent: dat vasten in week één nog moeite kost, zegt niets over of het bij je past. Je beoordeelt een gewoonte niet in de fase waarin hij nog geen gewoonte is. Geef het op zijn minst drie weken voordat je conclusies trekt.',array['any']::text[],null,false,null,'gebaseerd op één veelgeciteerde studie naar gewoontevorming; de spreiding tussen mensen is groot'),
('mind-c-14','mindset','Maak een als-danplan','Een voornemen als ''ik ga beter volhouden'' is te vaag om iets mee te doen. Een als-danplan werkt beter: als ik ''s avonds op de bank trek krijg, dan zet ik een pot thee. Als ik voor de kast sta, dan loop ik eerst een rondje door het huis. Je beslist op een rustig moment, zodat je op het zwakke moment alleen nog hoeft uit te voeren. Schrijf er vanavond twee op.',array['any']::text[],null,false,null,'als-danplannen zijn in meerdere studies bij mensen effectief gebleken'),
('pers-a-01','perspectief','Eén afspraak, geen regelboek','Een gemiddeld dieet komt met een lijst: dit wel, dat niet, zoveel gram, zoveel punten. Vasten komt met één afspraak: je eet binnen je venster, daarbuiten niet. Dat is alles. Geen boek te lezen, geen lijst op de koelkast, geen uitzonderingen om te onthouden. Eén regel onthoud je ook op een dag waarop je hoofd vol zit met werk en kinderen. Dat is precies waarom dit vol te houden is waar diëten sneuvelen.',array['any']::text[],null,false,null,null),
('pers-a-02','perspectief','Je hoeft niets te kopen','Geen shakes, geen maaltijdboxen, geen supplementen, geen abonnement, geen app met premium-versie. Vasten kost letterlijk niets. Sterker: je bespaart een ontbijt per dag en de tussendoortjes die erbij hoorden. Wees eerlijk sceptisch tegenover elke methode die je eerst iets wil verkopen. Deze methode heeft niets te verkopen. Dat zegt iets over hoe simpel het werkelijk is.',array['any']::text[],null,false,null,null),
('pers-a-03','perspectief','Gereedschap, geen religie','Vasten is een gereedschap, geen levensovertuiging. Je hoeft nergens lid van te worden en niemand te overtuigen. Werkt het voor je? Gebruik het. Past het een periode niet, bijvoorbeeld rond een vakantie of een drukke werkweek? Dan leg je het even weg en pak je het later weer op. Een hamer verwijt je ook niets als hij een week in de kast ligt. Wie er een identiteit van maakt, maakt het zwaarder dan nodig.',array['any']::text[],null,false,null,null),
('pers-a-04','perspectief','De ochtend die je terugkrijgt','Reken eens na wat je eigen ontbijt je kostte: smeren, eten, opruimen. Al gauw een kwartier tot twintig minuten, precies in het drukste uur van de dag. Dat kwartier is nu van jou. Broodtrommels vullen zonder zelf met een boterham in je hand te staan, of gewoon vijf minuten eerder de deur uit. Vasten levert je geen tijd op in theorie, maar in het uur waarin je die het hardst nodig hebt.',array['fast_early','fast_mid']::text[],null,false,null,null),
('pers-a-05','perspectief','Minder borden, minder gedoe','Elke maaltijd die je niet eet, is ook een maaltijd die je niet hoeft te bedenken, klaar te maken en af te wassen. Eén bord minder per dag klinkt als niets, maar tel het op: zeven borden, zeven messen, zeven keer kruimels van het aanrecht per week. Vasten wordt vaak verkocht als iets voor je lichaam. Het is ook gewoon minder huishouden. Voor een vader met jonge kinderen is dat geen bijzaak.',array['fast_early','fast_mid']::text[],null,false,null,null),
('pers-a-06','perspectief','De rust als eetbeslissingen wegvallen','Mag ik dit tussendoortje, is dit een goed moment, wat neem ik straks: wie op zijn eten let, is er de hele dag mee bezig. Zolang je venster dicht is, bestaat die hele categorie vragen niet. Het antwoord is steeds hetzelfde: nu niet, straks wel. Veel mannen merken dat juist die stilte in hun hoofd het grootste winstpunt is, meer nog dan de kilo''s. Je hoeft nergens over te onderhandelen met jezelf.',array['fast_mid','fast_late']::text[],null,false,null,null),
('pers-a-07','perspectief','Hoe lang hield je het tellen vol','Denk terug aan eerdere pogingen om op je eten te letten. Hoe lang bleef je calorieën invoeren in een app, twee weken, drie? Niet omdat je zwak was, maar omdat bijhouden zelf werk is, en werk dat nooit af is verlies je. Bij vasten valt er niets bij te houden. De klok loopt vanzelf, of jij nou oplet of niet. Een methode zonder administratie kan niet sneuvelen op de administratie.',array['any']::text[],null,false,null,null),
('pers-a-08','perspectief','Je boodschappenkar blijft hetzelfde','Vergelijk het met een collega die keto doet: aparte producten, aparte pannen, discussie aan tafel. Jouw gezin merkt aan de boodschappen niets van jouw vasten. Zelfde brood, zelfde avondeten, zelfde kar bij de supermarkt. Jij eet alleen op andere tijden. Een aanpak die geen enkele aanpassing van je gezin vraagt, heeft één probleembron minder, en dat scheelt op de lange duur meer dan je denkt.',array['any']::text[],null,false,null,null),
('pers-a-09','perspectief','Volhouden verslaat het perfecte dieet','Onderzoek dat diëten vergelijkt, laat telkens hetzelfde zien: het maakt voor gewichtsverlies weinig uit welk dieet je kiest, het maakt uit of je het volhoudt. Therapietrouw voorspelt het resultaat beter dan de methode. Bekeken door die bril is de vraag niet of vasten het beste is, maar of het de aanpak is die jij over een jaar nog doet. Voor veel drukke vaders is één simpele tijdsafspraak precies dat.',array['any']::text[],null,false,null,'vergelijkende dieetstudies bij mensen; therapietrouw voorspelt het resultaat consistenter dan het dieettype'),
('pers-a-10','perspectief','Vasten zegt niets over wát je eet','Elk dieet dat je kent verdeelt eten in goed en fout. Vasten doet dat niet: het gaat alleen over wanneer, niet over wat. Dat scheelt schuldgevoel bij elke maaltijd en gezeur in je hoofd bij elke keuze. Let wel op: het is geen vrijbrief om alleen nog troep te eten, gezond blijft gewoon verstandig. Maar je hoeft geen enkele lijst met verboden producten uit je hoofd te leren. Het venster is de enige grens.',array['eat_open','eat_mid']::text[],null,false,null,null),
('pers-a-11','perspectief','Het enige wat je nu moet doen is niets','Op dit moment vraagt vasten precies nul handelingen van je. Geen maaltijd afwegen, niets bereiden, niets invoeren, niets kiezen. Elk ander dieet eist juist op de zware momenten actie en discipline. Dit vraagt alleen dat je even niets doet, en niets doen kun je overal: in de auto, op je werk, met een kind op je arm. Sta het uit zoals je een file uitzit: zonder er iets van te vinden.',array['fast_mid','fast_late']::text[],null,true,'Zet een grote pot thee.',null),
('pers-a-12','perspectief','Op dit moment doe je alles goed','Terwijl je dit leest, doe je alles goed. Er is maar één afspraak en die houd je op dit moment. Geen half bijgehouden app, geen vergeten weegmoment, geen gemiste puntentelling die je vanavond moet inhalen. Dit systeem kent maar één onderdeel en dat onderdeel draait. Zo simpel is het, en precies daarom hou je dit langer vol dan alles wat je hiervoor probeerde.',array['fast_late']::text[],null,true,'Drink een groot glas water.',null),
('pers-b-01','perspectief','Vasten of gewoon minder eten: wat studies zeggen','Gerandomiseerde studies vergeleken intermittent fasting met gewoon dagelijks minder eten. De uitkomst is nuchter: het gewichtsverlies is ongeveer gelijk. Een apart metabool voordeel van vasten is bij mensen niet overtuigend aangetoond. Vasten werkt vooral omdat je er in de praktijk minder calorieën door binnenkrijgt. Dat is geen zwakte van de methode, het is de methode. Verwacht dus geen wondereffect naast het minder eten, en beoordeel je aanpak op één vraag: eet je hiermee structureel minder zonder dat het je leven overneemt.',array['any']::text[],null,false,null,'meerdere gerandomiseerde studies bij mensen die vasten vergeleken met klassiek calorieën beperken'),
('pers-b-02','perspectief','Een halve kilo per week is een goed tempo','Reken na de eerste weken op een kwart tot een halve kilo per week. Bij een hoger startgewicht mag het iets sneller, grofweg een half tot één procent van je lichaamsgewicht. Meer dan dat gaat zelden lang goed: je verliest dan ook spiermassa en het is zwaarder vol te houden. Op papier is een halve kilo per week ruim twintig kilo per jaar. In de praktijk wordt dat minder door vlakke weken, en ook dat is normaal. Wie tien kilo kwijt wil, moet in maanden denken. Niet in weken.',array['any']::text[],null,false,null,null),
('pers-b-03','perspectief','De eerste kilo''s zijn vooral vocht','Zakt de weegschaal in week één met twee of drie kilo, dan is dat grotendeels vocht. Je koolhydraatvoorraad houdt water vast; eet je minder, dan verdwijnt dat water eerst. Echt vetverlies gaat trager. De terugval naar een paar ons per week in week drie is dus geen stagnatie, maar het begin van het echte werk. Wie dit niet weet, haakt precies op dat moment af. Wie het wel weet, kijkt er doorheen.',array['fast_early','fast_mid']::text[],null,false,null,null),
('pers-b-04','perspectief','Weeg de trend, niet de dag','Weeg jezelf op een vast moment: na het opstaan, na de wc, in dezelfde kleren of zonder. Noteer het getal en kijk pas na vier weken naar de lijn. Dagschommelingen van één tot twee kilo zijn vocht, zout en darminhoud, geen vet. Gewichtsverlies loopt bovendien niet in een rechte lijn: twee vlakke weken en dan ineens een sprong komt vaak voor. De trend over een maand zegt iets. Eén ochtend zegt bijna niets.',array['fast_early']::text[],null,false,null,null),
('pers-b-05','perspectief','Waarom langzaam wint van snel','Snelle diëten leveren snel resultaat en meestal ook snelle terugkeer. Uit onderzoek naar gewichtsbehoud blijkt dat het verloren gewicht na een streng dieet vaak binnen enkele jaren terug is. Langzaam afvallen heeft twee voordelen. Je verliest minder spiermassa, en de gewoontes die je opbouwt passen in je gewone leven, met werk en kinderen erbij. Een aanpak die je op een doordeweekse dinsdag met een ziek kind nog volhoudt, is meer waard dan een aanpak die alleen in een rustige week werkt.',array['any']::text[],null,false,null,'onderzoek naar gewichtsbehoud na afvalpogingen'),
('pers-b-06','perspectief','Ken je die vorige poging nog','Denk terug aan je snelste afvalpoging. Hoeveel kilo ging eraf, en waar stond je een jaar later? Voor de meeste mannen is dat een ongemakkelijke som. Het probleem was niet je discipline, maar het tempo: wat snel gaat, is meestal niet gebouwd om te blijven. Stel jezelf daarom een andere vraag dan vorige keer. Niet: hoe snel kan ik zakken. Wel: welk gewicht kan ik over vijf jaar nog steeds vasthouden, met dit werk en deze kinderen.',array['any']::text[],null,false,null,null),
('pers-b-07','perspectief','Op gewicht blijven is de echte klus','Je doelgewicht halen is niet het einde, het is een overgang. Wie alle structuur loslaat, ziet het gewicht meestal terugkomen. Praktischer: verruim je venster stap voor stap, bijvoorbeeld van zestien naar veertien uur vasten, en blijf wekelijks wegen. Spreek met jezelf een grens af, bijvoorbeeld twee kilo boven je doel. Kom je daarboven, dan ga je tijdelijk terug naar het strakkere schema. Mensen die hun gewicht jarenlang vasthouden, blijven vrijwel allemaal monitoren. Niet spannend, wel effectief.',array['any']::text[],null,false,null,'gegevens van mensen die gewichtsverlies langdurig vasthouden, o.a. registeronderzoek'),
('pers-b-08','perspectief','Een lichter lijf vraagt minder brandstof','Tien kilo lichter betekent dat je lichaam dagelijks een paar honderd calorieën minder nodig heeft. Dat is geen kapot metabolisme, dat is rekenwerk: minder massa kost minder energie. Het verklaart waarom je oude porties je oude gewicht terugbrengen, ook als je verder niets fout doet. Houd daar rekening mee als je venster straks ruimer wordt. Je nieuwe onderhoudsniveau ligt lager dan wat je at toen je begon. Wie dat accepteert, hoeft zich later niet af te vragen waar die kilo''s vandaan komen.',array['eat_mid','eat_close']::text[],null,false,null,null),
('pers-b-09','perspectief','Fit de vijftig voorbij','Minder gewicht is minder last op je knieën en je rug, elke traptrede opnieuw. Het verschil merk je niet volgende week, wel over tien jaar: op de fiets, op het schoolplein, bij het sjouwen met fietsjes en boodschappen. Fit blijven na je veertigste is geen project van maanden maar van jaren, en de uren die je nu vast zijn daar gewoon onderdeel van. Je bouwt aan de versie van jezelf die op zijn vijftigste nog makkelijk beweegt.',array['fast_mid','fast_late']::text[],null,true,'Ga tien minuten stevig wandelen.',null),
('pers-b-10','perspectief','Reken eens veertien jaar vooruit','Tel veertien jaar op bij je leeftijd. Zo oud ben je als je kind van vier achttien wordt. Hoe die jaren voelen, hangt van veel af dat je niet stuurt, en van een paar dingen die je wel stuurt. Gewicht hoort bij die tweede categorie. Een gezond gewicht geeft geen garanties, het verschuift kansen. Meer niet, maar ook niet minder. Dat is geen reden voor drama, wel een nuchtere reden om vandaag vol te houden.',array['fast_late']::text[],null,true,'Bekijk een foto van je kinderen.',null),
('pers-b-11','perspectief','Dit uur is één datapunt','Dit zware uur is er één van de bijna zesduizend wakkere uren die dit jaar telt. In de optelsom van twaalf maanden weegt het vrijwel niets, wat het nu ook van je vraagt. Wat telt is het gemiddelde over maanden: hoe vaak je venster klopte, niet hoe zwaar één donderdagmiddag was. Zoom uit. Over een jaar weet je niet meer welke dag dit was. Wel wat de weegschaal en de trap dan zeggen.',array['fast_late']::text[],null,true,'Schrijf op waar je over een jaar wilt staan.',null),
('pers-b-12','perspectief','Wat betekent geslaagd over vijf jaar','Bepaal voor jezelf wat geslaagd betekent over vijf jaar. Waarschijnlijk is het geen getal op de weegschaal maar iets praktisch: de trap op zonder hijgen, een kind op je schouders zonder na te denken, kleren die gewoon passen. Schrijf twee of drie van die concrete ijkpunten op. De weegschaal is een hulpmiddel om daar te komen, geen doel op zich. Gaan je ijkpunten vooruit terwijl het getal even stilstaat, dan gaat het alsnog de goede kant op.',array['any']::text[],null,false,null,null),
('prak-a-01','praktisch','Zwarte koffie breekt je vast niet','Zwarte koffie bevat vrijwel geen calorieën, twee tot vijf per kop. Je insulinespiegel blijft er in de praktijk gewoon laag bij. Voor vrijwel elke vorm van intermittent fasting geldt daarom: zwarte koffie mag. Cafeïne dempt bovendien licht je eetlust, wat de ochtenduren makkelijker maakt. De voorwaarde is wel echt zwart. Geen suiker, geen melk, geen siroop. Espresso, filterkoffie, americano, cold brew: allemaal prima, zolang er niets in gaat.',array['fast_early','fast_mid']::text[],null,true,'Zet een kop zwarte koffie.','eetlustdemping door cafeïne is bescheiden en verschilt per persoon'),
('prak-a-02','praktisch','Thee mag, zolang er niets in gaat','Groene thee, zwarte thee, kruidenthee, verse muntthee: allemaal vrijwel calorievrij en dus geen probleem tijdens je vast. Let op twee dingen. Melk en suiker zijn uit den boze, en veel kant-en-klare theedranken uit de supermarkt zitten vol suiker. Zet hem dus zelf. Warme thee heeft nog een voordeel: hij vult je maag tijdelijk en geeft je handen iets te doen. Wissel af met koffie, dan blijft je cafeïne-inname binnen de perken.',array['fast_early','fast_mid','fast_late']::text[],null,false,null,null),
('prak-a-03','praktisch','Twee tot drie liter water op een vastendag','Op een normale dag haal je zo''n twintig procent van je vocht uit eten. Op een vastendag valt dat weg, dus moet je meer drinken dan je gewend bent. Reken op twee tot drie liter, verdeeld over de dag. Praktisch: vul ''s ochtends een fles van een liter en zorg dat die voor de lunch leeg is. Je urine is een prima meter. Lichtgeel is goed, donker betekent bijdrinken. Dorst voelt bovendien soms als honger, dus drink eerst voordat je concludeert dat je moet eten.',array['fast_early','fast_mid','fast_late']::text[],null,true,'Drink een groot glas water.',null),
('prak-a-04','praktisch','Bruiswater: wapen tegen een hongergolf','Nul calorieën, geen suiker: bruiswater breekt je vast niet. Het heeft zelfs een voordeel boven plat water. De koolzuurbubbels rekken je maag iets op, waardoor een hongergolf sneller wegzakt. Een klein aantal studies wijst erop dat koolzuurhoudend water het gevoel van verzadiging kort verhoogt. Zet een paar flessen koud en pak er een op het moment dat het knaagt. Kies wel gewoon bruiswater, geen light-frisdrank met smaakjes als je zoetstoffen liever mijdt.',array['fast_mid','fast_late']::text[],null,true,'Drink een glas koud bruiswater.','klein aantal kleine studies naar verzadiging bij mensen'),
('prak-a-05','praktisch','Een scheutje melk: strikt fout, praktisch oké','Strikt genomen breekt een scheutje melk je vast: er zitten calorieën en wat melksuiker in, dus je insuline reageert er licht op. Praktisch gezien stelt het weinig voor. Tien milliliter melk is ongeveer vijf calorieën. Als een wolkje melk het verschil maakt tussen volhouden en stoppen, kies dan voor volhouden. Val je af en werkt het? Dan doet dat scheutje er niet toe. Wil je puristisch vasten, laat het dan weg. Beslis het één keer en blijf er daarna vanaf.',array['fast_early','fast_mid']::text[],null,false,null,null),
('prak-a-06','praktisch','Zoetstoffen tijdens het vasten: de eerlijke stand','Breekt light-frisdrank je vast? Niemand weet het zeker. Zoetstoffen bevatten vrijwel geen calorieën, maar het onderzoek naar hun effect op insuline en eetlust spreekt elkaar tegen. Sommige studies zien niets, andere zien een kleine reactie of meer trek later. Wees dus pragmatisch. Helpt een colaatje light je van de koekjes af, dan is het per saldo winst. Merk je dat zoet drinken je juist hongerig maakt, laat het dan staan. Test het op jezelf, dat zegt hier meer dan de studies.',array['fast_mid','fast_late']::text[],null,false,null,'onderzoek bij mensen is niet eenduidig'),
('prak-a-07','praktisch','Kauwgom in de vast: geen ramp','In de file of achter je bureau wordt de drang om iets in je mond te stoppen soms groot. Een suikervrije kauwgom helpt daar prima tegen. Er zitten een paar calorieën en wat zoetstof in, daar gaat je vast niet van kapot. Wel een eerlijke kanttekening: kauwen zet je spijsvertering alvast aan en wekt bij sommigen juist honger op. Merk je dat, dan stop je ermee. Voor de meesten is het een handig hulpmiddel, geen bedreiging.',array['fast_mid','fast_late']::text[],null,true,'Neem een suikervrije kauwgom.',null),
('prak-a-08','praktisch','Een kop bouillon voor de zware uren','Bouillon is technisch gezien eten: een kop bevat al snel tien tot twintig calorieën. Wie strikt vast, slaat hem dus over. Maar in de laatste zware uren voor je eetvenster kan een kop warme bouillon precies het verschil maken. Je krijgt er zout en vocht mee binnen, warmte in je maag, en het gevoel dat je iets hebt gehad. Voor je vetverbranding maken die paar calorieën vrijwel niets uit. Zie het als noodrem, niet als dagelijkse gewoonte.',array['fast_late']::text[],null,true,'Maak een kop warme bouillon.',null),
('prak-a-09','praktisch','Zout en elektrolyten breken je vast niet','Als je vast, daalt je insuline en scheiden je nieren meer natrium uit. Je plast dus zout weg. Puur zout, magnesium en kalium bevatten geen calorieën en breken je vast niet. Een mespunt zout in een glas water, of een elektrolytenpoeder zonder suiker, kan daarom prima binnen je vastenuren. Let bij kant-en-klare elektrolytendrankjes wel op het etiket: veel sportdranken zitten vol suiker en die breken je vast wél. Twijfel je vanwege hoge bloeddruk of medicijnen, overleg dan met de huisarts.',array['fast_mid','fast_late']::text[],null,false,null,null),
('prak-a-10','praktisch','Onderweg koffie halen: bestel hem zwart','Je staat bij het tankstation of op het perron en bestelt uit gewoonte een cappuccino. Daar zit zo''n honderd milliliter melk in, ruwweg vijftig calorieën, en daarmee is je vast gewoon voorbij. Een latte is nog erger. De veilige bestellingen zijn espresso, zwarte filterkoffie of een americano. Zeg er meteen bij dat je geen melk wilt, want bij veel automaten en baristakoffie gaat die er standaard in. Eén keer scherp bestellen is makkelijker dan achteraf balen.',array['fast_early','fast_mid']::text[],null,false,null,null),
('prak-a-11','praktisch','Eén simpele drinkregel stopt het getwijfel','Telt dit nou wel of niet? Die discussie met jezelf kost meer energie dan de vast zelf. Hanteer daarom één regel: tijdens de vastenuren drink je alleen wat vrijwel geen calorieën bevat. Water, bruiswater, zwarte koffie en thee zonder iets erin. Al de rest hoort bij je eetvenster. Klaar. Je hoeft dan nooit meer per geval na te denken of iets mag, en juist dat maakt vasten vol te houden op dagen dat je hoofd al vol zit.',array['any']::text[],null,false,null,null),
('prak-a-12','praktisch','Meer koffie is niet altijd beter','Koffie mag tijdens het vasten, maar zes koppen op een lege maag is een ander verhaal. Te veel cafeïne geeft een opgejaagd gevoel, maagklachten en bij sommigen juist meer trek. En cafeïne na een uur of twee ''s middags kan je slaap verstoren, precies wat je met jonge kinderen niet kunt gebruiken. Houd het op twee tot vier koppen, drink er water naast en schakel in de middag over op cafeïnevrij of kruidenthee. Dan houd je het voordeel zonder de bijwerkingen.',array['fast_mid','fast_late']::text[],null,false,null,null),
('prak-a-13','praktisch','Kruidenthee als slotsignaal van de dag','Het eetvenster is dicht, de kinderen liggen in bed, en juist dan begint het gesnaai op de bank. Een grote mok kruidenthee werkt dan als signaal: de keuken is gesloten. Geen calorieën, geen cafeïne, dus ook je nachtrust blijft heel. Munt, kamille, rooibos, wat je lekker vindt. Het ritueel van zetten en langzaam leegdrinken overbrugt precies het eerste, moeilijkste uur van je vast. Zet de waterkoker klaar zodra je de laatste hap van de dag neemt.',array['eat_close','fast_early']::text[],null,false,null,null),
('prak-a-14','praktisch','Deze drankjes breken je vast wél','Sap, ook vers geperst, is vloeibare suiker. Een smoothie is een maaltijd. Sportdrank, ijsthee, chocolademelk, havermelk in je koffie, een gezond ogend shotje gember met sinaasappel: het breekt allemaal je vast. Zelfs een lepeltje honing in de thee telt, dat is pure suiker. De vuistregel is simpel. Smaakt het zoet of romig en komt het niet uit de zoetstoffenhoek, dan hoort het in je eetvenster. Lees bij twijfel het etiket: staan er koolhydraten of vetten op, dan wachten tot het venster opent.',array['fast_early','fast_mid','fast_late']::text[],null,false,null,null),
('prak-a-15','praktisch','Cafeïnevrije koffie mag ook gewoon','Cafeïnevrije koffie is een ondergewaardeerde optie. Hij bevat net als gewone koffie vrijwel geen calorieën en breekt je vast dus niet; het decafeïneren voegt niets toe wat je vast verstoort. Zo houd je ''s middags het ritueel, de smaak en de warme mok in je handen, zonder cafeïne die tot in de avond doorwerkt en je slaap sloopt. Handig voor wie zijn eetvenster laat op de dag opent en de middag moet overbruggen, of voor wie ''s ochtends al aan zijn cafeïnegrens zit.',array['fast_mid','fast_late']::text[],null,false,null,null),
('prak-a-16','praktisch','Smaak in je water zonder je vast te breken','Plat water verveelt snel als je er twee liter per dag van moet drinken. Een schijfje citroen, wat komkommer of een takje munt in een kan water geeft smaak en stelt calorisch niets voor, hooguit twee of drie calorieën. Dat breekt je vast niet. Kant-en-klaar water met een smaakje is een ander verhaal: check het etiket op suiker en zoetstoffen. En siroop, ook de suikervrije variant, valt onder de zoetstoffendiscussie. Zelf iets in een kan snijden is de veiligste route.',array['fast_early','fast_mid','fast_late']::text[],null,false,null,null),
('prak-b-01','praktisch','Hoofdpijn in week één: pak zout en water','De meest gemelde klacht in de eerste week is hoofdpijn. Vaak is het geen honger maar een tekort aan vocht en zout. De oplossing is simpel: drink een groot glas water met een flinke snuf zout erin. Smaakt niet geweldig, werkt bij veel mensen binnen een half uur. Herhaal het gerust een paar uur later. Houdt de hoofdpijn na de eerste week aan, dan is dat een reden om even met de huisarts te overleggen.',array['fast_mid','fast_late']::text[],null,true,'Los een snuf zout op in een groot glas water en drink het op.','werkzaamheid van extra zout is weinig formeel onderzocht; vooral praktijkervaring'),
('prak-b-02','praktisch','Waarom je kop bonkt als je niets eet','Hoofdpijn in de eerste week heeft zelden met honger te maken. Als je stopt met de hele dag eten, houden je nieren tijdelijk minder natrium en vocht vast. Dat verlies merk je als bonkende hoofdpijn of een licht gevoel in je hoofd. Het is een overgangsverschijnsel, geen teken dat vasten niet bij je past. Meestal ebt het na een week weg. Drink ruim water en wees in je eetvenster niet zuinig met zout op je eten.',array['fast_mid','fast_late']::text[],null,false,null,'mechanisme goed beschreven; hoe sterk klachten optreden verschilt per persoon'),
('prak-b-03','praktisch','Duizelig bij het opstaan uit je bureaustoel','Sta je op van je bureaustoel en wordt het even zwart voor je ogen? Dat komt doordat je bloeddruk in de eerste vastenweken wat lager kan liggen, mede door vochtverlies. Meestal onschuldig, wel onhandig. Sta rustig op: eerst even zitten op de rand, dan pas lopen. Drink daarnaast meer water dan je gewend bent. Word je regelmatig duizelig, ook zonder op te staan, of val je bijna flauw, neem het dan serieus en bel de huisarts.',array['fast_mid','fast_late']::text[],null,true,'Ga even zitten, drink een glas water en sta daarna langzaam op.',null),
('prak-b-04','praktisch','Koude handen tijdens het vasten zijn normaal','Veel mensen krijgen tijdens langere vastenuren koude handen en voeten. Je lichaam verlegt de doorbloeding iets meer naar je kern en organen. Vervelend achter een toetsenbord, maar meestal onschuldig. Wat helpt: een warme kop thee tussen je handen, vijf minuten stevig de trap op en neer, of gewoon een extra trui. Het verdwijnt zodra je gegeten hebt.',array['fast_mid','fast_late']::text[],null,true,'Zet een kop hete thee en warm je handen eraan.','weinig onderzocht verschijnsel; breed gemeld in de praktijk'),
('prak-b-05','praktisch','De lunchafspraak die midden in je vast valt','Klant wil lunchen om half één, jouw venster opent pas om drie uur. Je hebt drie opties. Eén: schuif aan, bestel zwarte koffie of bruiswater en voer gewoon het gesprek. Niemand let zo op jouw bord als jij denkt. Twee: verschuif je venster die dag naar voren en vast ''s avonds langer. Drie: stel voor om te wandelen in plaats van te lunchen. Kies vooraf, niet ter plekke met de menukaart in je hand.',array['fast_mid']::text[],null,false,null,null),
('prak-b-06','praktisch','Het teamuitje is geen reden om te stoppen','Een borrel om vier uur, een teamuitje met barbecue: het gebeurt een paar keer per jaar. Behandel het als een uitzondering, niet als een test die je kunt zakken. Verschuif die dag je venster zodat het uitje erin valt, of doe gewoon mee en pak morgen je normale ritme weer op. Een schema dat nooit ruimte biedt voor je werk en je collega''s houd je niet vol. Het gaat om wat je de andere vijftig weken doet.',array['any']::text[],null,false,null,null),
('prak-b-07','praktisch','''Ik lunch later'' is een compleet antwoord','Je hoeft op werk geen presentatie te geven over intermittent fasting. Ervaring leert: hoe langer je uitleg, hoe meer discussie je krijgt. ''Ik lunch vandaag later'' of ''ik heb al wat gepland'' is genoeg. Klopt allebei, want je eet later ook echt. Wil iemand er oprecht meer over weten, dan kun je altijd nog vertellen hoe je het aanpakt. Maar de bewijslast ligt niet bij jou. Wat je eet, en wanneer, is geen agendapunt.',array['fast_mid']::text[],null,false,null,null),
('prak-b-08','praktisch','Broodjes bij de vergadering, jij zit te vasten','Lunchvergadering, schaal broodjes op tafel. Pak een koffie, doe mee met het overleg en laat de broodjes staan. Voelt de eerste keer ongemakkelijk, daarna niet meer. Merk je dat het lastig blijft, leg dan een broodje op een servet naast je laptop en eet het als je venster opent. Niemand houdt bij wanneer jij je broodje eet. En eerlijk: de helft van de vergadering kijkt toch naar een scherm.',array['fast_mid']::text[],null,false,null,null),
('prak-b-09','praktisch','Open je venster rustig, niet met een aanval','Na zestien uur zonder eten wil je maag even op gang komen. Prop je hem direct vol, dan krijg je vaak buikpijn, een opgeblazen gevoel of een dip een uur later. Begin daarom klein: wat yoghurt met noten, een gekookt ei, een banaan. Wacht daarna een kwartier en eet dan je echte maaltijd. Dat kwartier vult zich vanzelf, met kinderen in huis. Je haalt niets in door snel te eten. Het eetvenster is lang genoeg.',array['fast_late','eat_open']::text[],null,false,null,null),
('prak-b-10','praktisch','Eerste maaltijd: aan tafel, niet boven het aanrecht','Herken je dit: venster open, koelkastdeur open, en tien minuten later heb je staand kaas, crackers en een handje pinda''s weggewerkt zonder er iets van gemerkt te hebben. Staand eten registreert je hoofd nauwelijks. Maak er daarom een vast punt van: je eerste eetmoment gaat op een bord en je zit erbij. Kost twee minuten extra. Het verschil is dat je daarna weet wát je gegeten hebt, en het gevoel hebt dat je gegeten hebt.',array['eat_open']::text[],null,false,null,null),
('prak-b-11','praktisch','Beslis om tien uur wat je om vier uur eet','Een hongerig brein kiest anders dan een verzadigd brein. Als je pas bedenkt wat je gaat eten op het moment dat je venster opent, wint meestal het snelste, vetste of zoetste dat voorhanden is. Beslis daarom eerder op de dag, als de honger nog beheersbaar is, wat je eerste maaltijd wordt. Zet het desnoods in je agenda. Het klinkt overdreven voor iets simpels als eten. Probeer het een week en kijk wat het met je keuzes doet.',array['fast_early','fast_mid']::text[],null,false,null,null),
('prak-b-12','praktisch','Vijf minuten voorbereiding, geen chaos om vijf uur','Het eetvenster van een vader valt vaak samen met het drukste deel van de dag: kinderen ophalen, avondeten, bedritueel. Zonder plan wordt jouw eerste maaltijd dan een sliert losse happen tussen de bedrijven door. De oplossing hoeft niet groots. Zet ''s avonds na het koken één portie apart voor de volgende dag. Of kook standaard één portie extra. Zo ligt er altijd iets klaar dat je alleen hoeft op te warmen, precies op het moment dat je er geen hoofd voor hebt.',array['eat_mid','eat_close']::text[],null,false,null,null),
('prak-b-13','praktisch','De eerste week is de zwaarste, en dat is normaal','Dag twee tot en met vijf zijn voor de meeste beginners het lastigst: hoofdpijn, korte lontjes, een leeg gevoel rond je oude lunchtijd. Daarna went het merkbaar. Je lichaam en je gewoontes passen zich aan het nieuwe ritme aan. Dit is nergens hard in kaart gebracht met grote studies; het beeld komt vooral uit praktijkervaring. Maar het patroon is herkenbaar genoeg om er rekening mee te houden. Plan je eerste week dus niet in een week vol deadlines en verjaardagen.',array['fast_mid','fast_late']::text[],null,true,'Ga tien minuten naar buiten, weg van je bureau.','vooral praktijkervaring, weinig formeel onderzoek naar opstartklachten'),
('prak-b-14','praktisch','Slik je medicijnen, ga dan eerst langs de huisarts','Gebruik je medicatie voor diabetes of bloeddruk, overleg dan met je huisarts vóór je begint met vasten. Sommige middelen zijn afgestemd op vaste eetmomenten en kunnen bij vasten te sterk werken, met een te lage bloedsuiker of bloeddruk als gevolg. Dat is geen bangmakerij maar een kwestie van doseringen. Ook zonder medicatie geldt: aanhoudende duizeligheid, hartkloppingen of hoofdpijn die na de eerste week niet afneemt zijn redenen om even te bellen. Een gezond ritme hoort na de opstartfase geen klachten te geven.',array['any']::text[],null,false,null,null),
('prak-b-15','praktisch','Eén fles op je bureau doet het halve werk','Concrete techniek voor de werkdag: vul ''s ochtends een fles van een liter en zet hem naast je scherm. Leeg voor twaalf uur, daarna opnieuw vullen. Veel klachten uit de eerste weken, van hoofdpijn tot een hangerig gevoel, hangen deels samen met te weinig drinken. Zonder eetmomenten verdwijnen ook je vaste drinkmomenten, dus dat gaat vanzelf mis. Met de fles in beeld hoef je er niet over na te denken; hij herinnert je er de hele ochtend aan.',array['fast_early','fast_mid']::text[],null,true,'Vul een grote fles water en zet hem binnen handbereik.',null),
('prak-b-16','praktisch','Welke lunchafspraak staat er deze week gepland','Open je agenda en kijk naar de komende vijf werkdagen. Staat er een lunchmeeting, een klantafspraak rond etenstijd, een afscheidsborrel? Beslis nu alvast per afspraak wat je doet: venster verschuiven, aanschuiven met koffie, of die dag gewoon meedoen. De momenten waarop vasten op werk lastig wordt, zijn bijna altijd van tevoren bekend. Wie op maandag vijf minuten vooruitkijkt, hoeft de rest van de week niets meer te improviseren.',array['any']::text[],null,false,null,null),
('sport-a-01','sport','Wandelen kan altijd, ook diep in de vast','Een stevige wandeling vraagt zo weinig van je lichaam dat je hem op elk punt in de vast kunt doen. De intensiteit is laag genoeg om vrijwel volledig op vet te draaien, de brandstof die je nuchter ruim voorradig hebt. Je hoeft er niets voor te plannen of aan te passen. Voel je je zwaar rond het einde van de vast, dan is een rondje lopen vaak juist prettiger dan stilzitten.',array['fast_early','fast_mid','fast_late']::text[],null,true,'Ga twintig minuten stevig wandelen.',null),
('sport-a-02','sport','De praattest: zo weet je of het zone 2 is','Zone 2 klinkt technisch, maar de test is simpel: kun je tijdens het bewegen een gesprek voeren zonder naar adem te happen, dan zit je goed. Dit tempo draait grotendeels op vet en kan daarom prima nuchter. Ga je hijgen en moet je zinnen afbreken, dan ben je te hard aan het werk voor een lege maag. Zak terug tot praten weer lukt. Geen hartslagmeter nodig, je mond is de meter.',array['fast_mid','fast_late']::text[],true,false,null,null),
('sport-a-03','sport','Zware krachttraining diep in de vast: doe het niet','Zestien uur of langer niet gegeten en dan onder een zware stang stappen is een slecht plan. Je kracht is dan meestal minder, je concentratie ook, en juist bij zware samengestelde oefeningen is dat een veiligheidsrisico. Een verkeerde inschatting bij een squat of deadlift komt harder aan dan een matige duurloop. Licht werk kan wel; het maximale werk bewaar je voor een moment waarop je gegeten hebt.',array['fast_late']::text[],true,false,null,null),
('sport-a-04','sport','Intervallen en een lange vast gaan slecht samen','Sprintjes, HIIT en intensieve intervallen leunen zwaar op koolhydraten als snelle brandstof. Diep in een lange vast is die voorraad niet op zijn best, en dat merk je: de tijden zakken, de laatste herhalingen worden gruwelijk, en de kans dat je duizelig eindigt groeit. Je traint dan vooral het opgeven. Plan dit soort werk op momenten dat je niet lang nuchter bent, of accepteer dat de sessie minder oplevert.',array['fast_late']::text[],true,false,null,null),
('sport-a-05','sport','Deze signalen betekenen direct stoppen','Duizeligheid, zwart voor je ogen, trillende handen, koud zweet of plotselinge verwardheid: dit zijn geen tekenen van een goede training, dit zijn stopborden. Onderbreek de sessie, ga zitten en wacht tot het zakt. Eet of drink iets als het niet snel beter wordt; een gebroken vast is niets vergeleken met een val in de sportschool. Komt dit vaker terug bij nuchter trainen, bespreek het dan met je huisarts.',array['fast_mid','fast_late']::text[],true,false,null,null),
('sport-a-06','sport','Het verschil tussen zwaar en niet in orde','Zware benen, een lager tempo en trek zijn normale verschijnselen bij nuchter trainen, zeker in het begin. Daar kun je doorheen bewegen door rustiger aan te doen. Duizeligheid, sterretjes zien of een licht gevoel in je hoofd zijn iets anders: dat zijn signalen dat je lichaam nu tekortkomt, en daar train je niet doorheen. Leer die twee categorieën uit elkaar te houden. Bij de eerste pas je het tempo aan, bij de tweede stop je.',array['fast_mid','fast_late']::text[],true,false,null,null),
('sport-a-07','sport','Je lichaam leert nuchter bewegen','De eerste nuchtere trainingen voelen vaak houterig, alsof de tank halfleeg is. Dat verandert. Wie regelmatig nuchter beweegt, wordt na een paar weken merkbaar beter in het aanspreken van vet als brandstof; het lichaam past zich aan op wat je ervan vraagt. De sessie die nu taai voelt, is over een maand waarschijnlijk gewoon een training. Geef de aanpassing de tijd en houd de intensiteit intussen laag.',array['any']::text[],null,true,'Ga een blokje om in een rustig tempo.','verbeterde vetverbranding door nuchter trainen is bij mensen aangetoond, vooral bij duursporters'),
('sport-a-08','sport','Eerst slechter presteren hoort erbij','Je looptijden zakken in de eerste weken nuchter trainen en dat voelt als achteruitgang. Meestal is het tijdelijk. Onderzoek bij duursporters laat zien dat prestaties op rustige intensiteit na een gewenningsperiode vaak terugkeren naar het oude niveau, terwijl het lichaam intussen efficiënter vet leert gebruiken. Voor topprestaties op hoge intensiteit blijft nuchter een nadeel. Beoordeel je vooruitgang dus niet in week twee; kijk na een week of zes opnieuw.',array['any']::text[],true,false,null,'kleine studies bij getrainde sporters; individuele verschillen zijn groot'),
('sport-a-09','sport','Het buggy-rondje telt gewoon als beweging','Zaterdagochtend, jij nuchter, de kleine wil naar buiten. Perfect. Een uur achter de buggy of naast een kinderfiets is precies het soort rustige inspanning dat uitstekend in de vast past. Je hoeft er geen sportkleren voor aan en het vult de uren tot je eetvenster met iets nuttigs. Beweging hoeft niet op een schema te staan om te tellen. Twee vliegen: het kind is de deur uit geweest en jij hebt bewogen.',array['fast_early','fast_mid']::text[],null,true,'Pak de buggy en loop een rondje om het blok.',null),
('sport-a-10','sport','Nuchter bewegen verbrandt meer vet, met een maar','Tijdens rustige nuchtere beweging haalt je lichaam een groter deel van zijn energie uit vet dan na een maaltijd. Dat is goed gemeten en klopt. De eerlijke kanttekening: meer vetverbranding tijdens de sessie betekent niet automatisch meer vetverlies over de hele week, want daarvoor telt vooral je totale energiebalans. Zie het dus niet als truc om sneller af te vallen, wel als teken dat je lichaam nuchter prima uit de voeten kan.',array['fast_mid','fast_late']::text[],null,true,'Doe tien minuten rustige beweging, een blokje om telt.','hogere vetoxidatie tijdens de sessie is goed aangetoond; extra vetverlies op termijn niet'),
('sport-a-11','sport','Vraag jezelf af: kan deze sessie nuchter','Loop je trainingsweek eens langs met één vraag per sessie: kan dit nuchter of niet? Wandelen, rustig fietsen, een makkelijke duurloop en mobiliteitswerk: ja. Maximale krachttraining, sprintwerk en lange intensieve sessies: liever niet diep in de vast. Wie dat onderscheid één keer scherp maakt, hoeft er daarna niet meer per keer over na te denken. Het schema beslist, niet je stemming van dat moment.',array['any']::text[],null,false,null,null),
('sport-a-12','sport','Je eerste nuchtere training: halveer alles','Begin niet met je normale sessie op een lege maag. Halveer de duur, verlaag het tempo en kijk hoe je lichaam reageert. Voelt het goed, dan bouw je de volgende keer iets op. Voelt het beroerd, dan weet je dat zonder dat je ergens ver van huis staat te tollen. Nuchter trainen is te leren, maar niemand zegt dat je bij de eerste poging het maximale moet bewijzen.',array['fast_early','fast_mid']::text[],true,false,null,null),
('sport-a-13','sport','Sterretjes tussen twee sets: leg de stang weg','Je staat achttien uur nuchter in de sportschool, derde set, en bij het omhoogkomen wordt het even zwart. Dat is het moment om de stang in het rek te leggen en te gaan zitten, niet om de set af te maken. Niemand in die zaal onthoudt jouw gemiste set; een flauwte onder gewicht onthoud je zelf nog lang. Drink wat, wacht, en maak er een lichte sessie van of stop helemaal.',array['fast_late']::text[],true,false,null,null),
('sport-a-14','sport','Doorzetten is hier geen prestatie','Bij hardlopen in de regen is doorzetten een kwaliteit. Bij nuchter trainen ligt dat anders: wie trillerig en licht in het hoofd toch doorgaat, bewijst niets en riskeert wel wat. De vast wordt niet waardevoller doordat je erin afziet, en de training wordt niet beter van een lichaam dat op reserve draait. Aanpassen of stoppen is bij nuchter sporten gewoon vakmanschap. Bewaar de heldendaden voor momenten met brandstof aan boord.',array['fast_mid','fast_late']::text[],true,false,null,null),
('sport-a-15','sport','Geen training vandaag? Beweeg toch even nuchter','Rustdagen zijn geschikte dagen om je lichaam aan nuchter bewegen te laten wennen, juist omdat er niets op het spel staat. Een half uur wandelen of rustig fietsen in de vast went je systeem aan inspanning zonder eten, zonder dat een prestatie eronder lijdt. Zo bouw je op de achtergrond gewenning op die je latere echte trainingen makkelijker maakt. Laagdrempeliger wordt oefenen niet.',array['fast_mid']::text[],false,false,null,null),
('sport-b-01','sport','Het anabole venster is geen halfuur','Het idee dat je binnen dertig minuten na krachttraining eiwit moet nemen, klopt niet. Onderzoek laat zien dat het venster eerder enkele uren beslaat, zeker als je eerder op de dag al gegeten hebt. Je totale eiwitinname per dag weegt zwaarder dan de exacte timing. Handig om te weten als vader: je hoeft niet met een shaker naast het bed van je kind te staan. Eet gewoon een stevige eiwitrijke maaltijd zodra het praktisch uitkomt binnen je venster.',array['eat_open','eat_mid']::text[],true,false,null,'meta-analyses vinden weinig effect van exacte timing zolang de totale eiwitinname gelijk is'),
('sport-b-02','sport','Train in het laatste uur van je vast','De laatste uren voor je venster opent zijn de zwaarste. Juist dan trainen is praktisch slim: je bent afgeleid, en direct na de training opent je venster en eet je precies wanneer je lichaam bouwstoffen kan gebruiken. Zo vallen honger, training en eerste maaltijd samen op één natuurlijk moment. Geen shakes op rare tijden, geen gedoe.',array['fast_late']::text[],true,true,'Pak je sporttas en ga trainen.',null),
('sport-b-03','sport','Schuif je venster op trainingsdagen','Je vaste venster hoeft niet elke dag identiek te zijn. Train je ''s avonds, schuif dan je hele venster een paar uur op: niet van twaalf tot acht, maar van twee tot tien. Zo kun je na de training nog een volwaardige maaltijd eten zonder je vastenduur in te korten. De consistentie zit in het aantal uren, niet in de klok.',array['any']::text[],true,false,null,null),
('sport-b-04','sport','Spierbehoud tijdens afvallen: twee knoppen','Afvallen zonder spierverlies vraagt om twee dingen: blijven krachttrainen en genoeg eiwit eten. Vasten zelf verandert daar weinig aan. Wie afvalt zonder te trainen, verliest naast vet ook spiermassa — dat geldt bij elk dieet, ook bij intermittent fasting. Krachttraining geeft je spieren de reden om te blijven, eiwit levert het materiaal. Twee tot drie trainingen per week is voor de meeste vaders al voldoende signaal.',array['any']::text[],null,false,null,null),
('sport-b-05','sport','Hoeveel eiwit heb je eigenlijk nodig','Richtlijn voor wie afvalt en krachttraint: ruwweg 1,6 tot 2,2 gram eiwit per kilo lichaamsgewicht per dag. Voor een man van 85 kilo is dat zo''n 140 tot 185 gram. Dat haal je niet per ongeluk uit twee maaltijden. Reken het een keer na met wat je op een normale dag eet. Grote kans dat je lager zit dan je denkt, zeker met een kort eetvenster.',array['any']::text[],null,false,null,'richtlijn uit sportvoedingsonderzoek; de exacte behoefte verschilt per persoon'),
('sport-b-06','sport','Je eerste maaltijd na de training','Na krachttraining is je eerste maaltijd het moment om eiwit binnen te krijgen: mik op 30 tot 40 gram. Praktisch: een flinke kom magere kwark met noten, drie eieren met een boterham kaas, of een bord met kip of vis. Trainde je nuchter, dan is snel eten na afloop iets belangrijker dan wanneer je eerder op de dag al eiwit had. Geen shake nodig; een gewone maaltijd volstaat.',array['eat_open']::text[],true,false,null,null),
('sport-b-07','sport','Trainen als de kinderen slapen','Kinderen om half acht in bed, om acht uur pas naar de sportschool. Herkenbaar schema, maar lastig als je venster om acht uur sluit. Twee opties: schuif je venster die dag twee uur op, of accepteer dat je na de training alleen nog iets eiwitrijks eet en verder niets. Beide zijn beter dan hongerig gaan slapen na een zware training, of de training maar overslaan.',array['eat_mid','eat_close']::text[],true,false,null,null),
('sport-b-08','sport','Verdeel je eiwit binnen het venster','Spieropbouw reageert per maaltijd: je lichaam gebruikt per eetmoment ongeveer 25 tot 40 gram eiwit optimaal voor spierherstel. Wie in een venster van acht uur maar twee keer eet, moet dus per maaltijd flink eiwit binnenkrijgen om aan zijn dagtotaal te komen. Verdeel het bewust: eiwit in beide maaltijden en eventueel een eiwitrijk tussendoortje ertussen. Alles in één avondmaal proppen werkt minder goed.',array['eat_open','eat_mid']::text[],null,false,null,'het plafond per maaltijd is in onderzoek niet hard vastgesteld; het dagtotaal weegt het zwaarst'),
('sport-b-09','sport','Past je venster bij je training','Wanneer train jij, en wanneer eet je? Zet die twee eens naast elkaar. Veel mannen plannen hun venster op de automatische piloot en hun training op de restjes tijd die overblijven. Draai het om: kies eerst je twee of drie vaste trainingsmomenten per week, en leg je eetvenster daaromheen. Training vlak voor of vroeg in het venster is de eenvoudigste combinatie.',array['any']::text[],null,false,null,null),
('sport-b-10','sport','Herstel is meer dan timing','Herstel na een training hangt maar beperkt af van wat je in het eerste uur eet. Slaap, je totale eiwit- en energie-inname over de volgende 24 tot 48 uur en de vraag of je überhaupt genoeg eet, wegen zwaarder. Met jonge kinderen is slaap vaak het zwakke punt. Een perfecte eiwittiming compenseert geen structureel tekort aan slaap. Kijk dus eerst daarnaar voordat je aan minuten gaat schaven.',array['any']::text[],true,false,null,null),
('sport-b-11','sport','Training uitgelopen, venster dicht','Soms loopt het anders: de training liep uit en je venster is net dicht. Wees er niet dogmatisch in. Af en toe na een zware krachttraining alsnog wat eiwit eten is een redelijke afweging, ook al kost het die dag een stukje vastenduur. Het alternatief: houd je venster dicht en eet morgen bij opening direct stevig eiwit. Niet perfect, maar één suboptimale keer maakt voor je spiermassa vrijwel niets uit.',array['eat_close','fast_early']::text[],true,false,null,null),
('sport-b-12','sport','Je spiermassa smelt niet weg','Je spieren verdwijnen niet door een dag vasten. Spierafbraak is een traag proces, en je lichaam heeft bovendien aminozuren in voorraad uit je laatste maaltijd. Wat spiermassa bepaalt is het patroon over weken: train je, en eet je per saldo genoeg eiwit? Dan houdt je lichaam vast wat je hebt opgebouwd. Dit zware moment nu verandert daar niets aan.',array['fast_mid','fast_late']::text[],null,true,'Schrijf op wat je straks als eerste eet.',null),
('sport-b-13','sport','Sluit een trainingsdag af met eiwit','Op een trainingsdag loont het om je laatste maaltijd voor het sluiten van het venster eiwitrijk af te maken. Een kom kwark of skyr is de klassieker. Daarna vast je een nacht plus een ochtend, en in die uren herstelt je lichaam op wat je nu binnenkrijgt. Onderzoek naar eiwit vlak voor het slapen laat een bescheiden voordeel zien voor spierherstel, geen wondermiddel.',array['eat_close']::text[],true,false,null,'klein aantal studies bij mensen; het effect is bescheiden'),
('sport-b-14','sport','De lunchtraining als dubbele oplossing','Werkdag, venster dat om één uur opent, en de zwaarste vastenuren vallen precies rond lunchtijd. Een lunchtraining lost twee dingen tegelijk op: de laatste hongerige uren vullen zich vanzelf, en direct erna eet je je eerste maaltijd als herstelmaaltijd. Een half uur krachttraining of een stevige workout thuis is genoeg. Je collega''s lunchen, jij traint en eet daarna.',array['fast_late']::text[],null,true,'Blok nu een half uur in je agenda voor een lunchtraining.',null),
('sport-b-15','sport','Eiwit telt ook op rustdagen','Rustdagen zijn geen pauze voor je eiwitbehoefte. Spierherstel loopt 24 tot 48 uur door na een training; ook op de dag erna bouwt je lichaam aan spierweefsel. Houd je eiwitinname op rustdagen dus op hetzelfde niveau als op trainingsdagen. Wat wel mag zakken: de totale hoeveelheid eten, want je verbruikt minder. Eiwit gelijk houden, de rest iets terugschroeven — zo simpel is het.',array['any']::text[],false,false,null,null),
('valk-a-01','valkuilen','Begin niet meteen met zestien uur','Veel mannen starten op maandag direct met 16:8 en zitten op donderdag chagrijnig aan de ontbijttafel. Je lichaam heeft tijd nodig om te wennen aan een nieuw eetritme. Begin met twaalf uur — dat is grotendeels slaap — en bouw per week een uur op. Dat voelt traag, maar je bent over een maand nog steeds bezig. Wie te snel te streng begint, stopt meestal binnen twee weken. Langzaam opbouwen is niet soft, het is de route met de hoogste slagingskans.',array['any']::text[],null,false,null,null),
('valk-a-02','valkuilen','Zestien uur vasten, in twee uur weer opgegeten','Zestien uur niet eten en dan in twee uur een dag aan calorieën naar binnen werken — dan schiet je er niets mee op. Intermittent fasting werkt voor gewicht vooral doordat je netto minder eet. Wie het venster opent met zakken chips en dubbele porties, heft dat effect volledig op. Begin je eetvenster daarom met een normale maaltijd die je vooraf hebt bedacht, niet met grazen door de keukenkastjes. Honger is een slechte kok en een nog slechtere boodschappenlijst.',array['fast_late','eat_open']::text[],null,false,null,'het effect op gewicht loopt in studies vooral via de totale energie-inname'),
('valk-a-03','valkuilen','Plan je eerste maaltijd voordat de honger dat doet','De laatste uren voor je venster opent, neemt de kans op overeten toe. Een concrete techniek: besluit wat je gaat eten vóórdat de honger het overneemt. Wat op je bord ligt is dan een beslissing van je uitgeruste ochtend-ik, niet van je hongerige middag-ik. Zet het desnoods alvast klaar. Wie zonder plan de keuken inloopt na zestien uur vasten, eet wat het snelst voorhanden is — en dat is zelden het beste.',array['fast_mid','fast_late']::text[],null,true,'Schrijf nu op wat je eerste maaltijd wordt.',null),
('valk-a-04','valkuilen','Meer uren vasten is niet automatisch beter','Het lijkt logisch: als zestien uur vasten werkt, werkt twintig uur beter. Zo werkt het niet. Onderzoek laat geen duidelijk voordeel zien van extreem korte eetvensters boven een gematigd schema, terwijl de kans dat je het volhoudt wél hard daalt. En een schema dat je na drie weken opgeeft, levert minder op dan een gematigd schema dat je jaren volhoudt. Vraag je bij elke aanscherping af: doe ik dit omdat het nodig is, of omdat meer beter voelt?',array['any']::text[],null,false,null,'vergelijkende studies tussen vensterlengtes zijn schaars en laten geen duidelijk verschil zien'),
('valk-a-05','valkuilen','De klok is geen scheidsrechter','Je venster opent om twaalf uur en om 11.58 sta je met een boterham in je hand. Is dat falen? Nee. Je lichaam kent geen harde grens tussen 15 uur en 58 minuten en 16 uur vasten; de processen die tijdens het vasten lopen, verschuiven geleidelijk. De grens is een afspraak met jezelf, geen biologische schakelaar. Perfectionisme op de minuut maakt het schema zwaarder dan nodig, zonder dat het iets extra''s oplevert.',array['fast_late','eat_open']::text[],null,false,null,null),
('valk-a-06','valkuilen','Hoe vaker je kijkt, hoe langzamer de klok','Hoe vaker je op de klok kijkt, hoe langzamer de tijd gaat en hoe groter de honger lijkt. Aandacht voedt het gevoel. Draai het om: koppel het einde van je vast aan een gebeurtenis in plaats van een tijdstip. Na de lunchwandeling. Als de kleine uit bed komt van zijn middagslaap. Gebeurtenissen komen vanzelf; een klok moet je bewaken. Wie zijn venster aan het ritme van de dag hangt, hoeft nergens meer op te letten.',array['fast_mid','fast_late']::text[],null,true,'Leg je telefoon weg en pak een taak van een kwartier.',null),
('valk-a-07','valkuilen','Zeg geen etentje af voor je schema','Een vriend vraagt of je komt eten en je twijfelt, omdat het buiten je venster valt. Let op: dan dient het schema jou niet meer, maar jij het schema. Schuif je venster die dag gewoon op, of laat het één keer los. Intermittent fasting is een gereedschap voor een normaal leven, geen vervanging ervan. Wie afspraken afzegt om zijn eetvenster, wint een paar uur vasten en verliest iets dat meer waard is.',array['any']::text[],null,false,null,null),
('valk-a-08','valkuilen','Na een lange vast eet je sneller dan je merkt','Verzadiging loopt achter op eten: het duurt zo''n vijftien tot twintig minuten voordat je hersenen doorkrijgen dat er genoeg binnen is. Na een lange vast eet je sneller, dus schuift dat moment op — je zit al aan je tweede bord voordat het eerste geregistreerd is. Praktisch: schep één keer op, ga zitten, leg je bestek tussen happen neer. Klinkt braaf, scheelt honderden calorieën. Juist de eerste maaltijd na het vasten bepaalt of je dag netto iets oplevert.',array['eat_open']::text[],null,false,null,null),
('valk-a-09','valkuilen','Alles tegelijk veranderen houdt niemand vol','Herkenbaar scenario: week één, vol enthousiasme. Achttien uur vasten, geen koffie meer, elke avond sporten, geen bier in het weekend. Week drie: alles tegelijk gestopt. Niet omdat vasten niet werkt, maar omdat niemand vier gedragsveranderingen tegelijk volhoudt naast een baan en jonge kinderen. Kies er één. Eerst het eetvenster, de rest komt later of helemaal niet. Eén verandering die blijft hangen verslaat vier die sneuvelen.',array['any']::text[],null,false,null,null),
('valk-a-10','valkuilen','Stilstand? Verleng niet meteen je vast','Na een paar maanden stokt de weegschaal en de reflex is: langer vasten. Maar stilstand komt meestal niet door te weinig vasturen. Vaker is het eetvenster geleidelijk voller geworden — grotere porties, meer tussendoor, een extra biertje. Kijk daar eerst naar voordat je van zestien naar achttien uur gaat. Een langer vast met een vol venster lost niets op en maakt je dagen onnodig zwaar. Hou het venster gelijk en kijk een week eerlijk naar wat erin gaat.',array['any']::text[],null,false,null,null),
('valk-a-11','valkuilen','Een goede dag is geen reden voor een strenger schema','Je zit op je geplande zestien uur en voelt je sterk. De verleiding: nog twee uur eraan plakken, record breken. Doe het niet standaard. De winst van intermittent fasting zit in de herhaling over maanden, niet in de uitschieter van vandaag. Een incidenteel langer vast kan geen kwaad, maar wie elke goede dag verzilvert met een strenger schema, bouwt aan een lat die steeds hoger ligt — tot hij eronderdoor gaat. Eet gewoon op je geplande tijd.',array['fast_late']::text[],null,false,null,null),
('valk-a-12','valkuilen','De eerste tien minuten van je venster zijn beslissend','Zwaar moment, venster bijna open, en het plan om rustig te eten voelt ver weg. Bouw dan een drempel in. Eerst een groot glas water, dan tafel dekken, dan pas de koelkast open. Die paar minuten vertraging halen de scherpste rand van de honger en geven je genoeg ruimte om te eten wat je van plan was in plaats van wat er het dichtst bij staat. Niet de zestien uur ervoor, maar deze tien minuten bepalen of je dag iets opgeleverd heeft.',array['fast_late','eat_open']::text[],null,true,'Drink een groot glas water voordat je iets eet.',null),
('valk-a-13','valkuilen','Streng is een middel, geen doel','Denk eens na over deze vraag: zou je je huidige schema aanraden aan je beste vriend met twee jonge kinderen en een drukke baan? Zo nee, waarom draai jij het dan wel? Strengheid voelt als daadkracht, maar het doel was nooit zo lang mogelijk niet eten. Het doel was fitter worden op een manier die in je leven past. Als je schema strenger is dan je een ander zou gunnen, ben je iets aan het bewijzen in plaats van iets aan het opbouwen.',array['any']::text[],null,false,null,null),
('valk-a-14','valkuilen','Bouw speling in je venster','Kinderen zijn slecht in plannen. De ene dag staat het avondeten om half zes op tafel, de andere dag om zeven uur omdat de zwemles uitliep. Een venster op de minuut vastleggen is daarom vragen om frustratie. Werk met een marge van een half uur aan beide kanten en beschouw alles daarbinnen als geslaagd. Voor je lichaam maakt dat halfuur nauwelijks iets uit; voor de houdbaarheid van je schema maakt het alles uit.',array['any']::text[],null,false,null,null),
('valk-b-01','valkuilen','Als vasten je gedachten begint te beheersen','Een goed hulpmiddel merk je nauwelijks op. Denk je de hele dag aan eten, tel je obsessief de uren, plan je afspraken alleen nog rond je venster? Dan is het gereedschap de baas geworden. Vasten hoort ruimte te geven in je hoofd, niet in te nemen. Merk je dat je gedachten er steeds naartoe trekken, ook tijdens werk of tijd met je kinderen, neem dat serieus. Versoepel je schema een paar weken en kijk wat er gebeurt.',array['any']::text[],null,false,null,null),
('valk-b-02','valkuilen','Verberg je het? Dan klopt er iets niet','Eet je stiekem als niemand kijkt, of doe je juist alsof je al gegeten hebt terwijl je vast? Verbergen is een klassiek waarschuwingssignaal bij verstoord eetgedrag. Wie een gezond schema volgt, kan er open over zijn tegen zijn partner. Vraag jezelf eerlijk af waarom je het niet vertelt. Schaamte over je eetpatroon is geen detail om weg te wuiven, maar een reden om het gesprek aan te gaan. Thuis, en als het aanhoudt met je huisarts.',array['any']::text[],null,false,null,null),
('valk-b-03','valkuilen','Doorbijten terwijl je lichaam protesteert','Trillende handen, koud zweet, hartbonzen, sterretjes zien als je opstaat: dit zijn geen tekenen van discipline maar van een lichaam dat protesteert. Doorvasten voelt op zo''n moment misschien stoer, maar het levert niets extra''s op en het traint je vooral in het negeren van signalen. Dat is precies de gewoonte die je niet wilt opbouwen. Eet dan gewoon iets en kijk morgen verder. Eén afgebroken vast zegt niets over je schema; structureel doorbijten terwijl je je ziek voelt zegt des te meer.',array['fast_mid','fast_late']::text[],null,true,'Ga even zitten en drink een groot glas water.',null),
('valk-b-04','valkuilen','Koorts of griep: dan vast je niet','Ziek zijn kost energie. Bij koorts verbruikt je lichaam meer en heeft je afweer brandstof en vocht nodig. Dit is geen moment om je venster te bewaken. Met jonge kinderen in huis komt er geregeld een virus mee van school of opvang; reken er dus op dat dit een paar keer per jaar gebeurt. Eet als je ziek bent gewoon verspreid over de dag, drink veel en pak het vasten weer op als je hersteld bent. Dat is geen terugval, dat is verstandig omgaan met je lichaam.',array['any']::text[],null,false,null,null),
('valk-b-05','valkuilen','Vasten is ook een stressor','Je lichaam telt alles bij elkaar op: krappe nachten, deadlines, een huis vol jonge kinderen én de uren zonder eten. Vasten is voor je lijf een milde stressor. Meestal geen probleem, maar in een periode waarin slaap structureel tekortschiet en de spanning hoog is, kan de stapel te groot worden. Signalen: slechter slapen dan voorheen, gejaagd gevoel, korter lontje dat niet meer wegtrekt. Kies dan tijdelijk een korter vastenvenster in plaats van stug doorgaan. De strengste variant op je zwaarste moment is zelden de slimste.',array['any']::text[],null,false,null,null),
('valk-b-06','valkuilen','Te snel afvallen is geen bonus','Meer dan een kilo per week verliezen, weken achter elkaar, klinkt als winst maar is meestal een waarschuwing. Bij zo''n tempo verlies je naast vet ook spiermassa, en de kans op terugveren wordt groter. Een halve tot één kilo per week is een gangbare vuistregel voor duurzaam afvallen. Gaat het structureel harder, dan eet je in je venster waarschijnlijk te weinig. Vasten regelt wanneer je eet, niet dat je nauwelijks eet. Weeg jezelf hooguit wekelijks, op hetzelfde moment, en kijk naar de trend over een maand.',array['any']::text[],null,false,null,'0,5 tot 1 kg per week is een algemene vuistregel, geen harde onderzoeksnorm'),
('valk-b-07','valkuilen','De sluipende signalen van te weinig eten','Let op sluipende signalen van een te groot energietekort: je hebt het voortdurend koud, je herstelt slecht van inspanning, je libido zakt weg, je haar wordt dunner of je bent constant moe. Los van elkaar zegt elk signaal weinig; samen vertellen ze dat je lichaam op de rem trapt. Dit is geen kwestie van doorzetten maar van bijsturen: ruimer eten in je venster of minder vastendagen. Houden de klachten aan, ook nadat je hebt bijgestuurd, bespreek het dan met je huisarts.',array['any']::text[],null,false,null,null),
('valk-b-08','valkuilen','Pauzeren is onderhoud, geen zwakte','Een week niet vasten betekent niet dat je het niet volhoudt. Sporters plannen rustweken omdat herstel onderdeel is van beter worden; met vasten werkt dat niet anders. Het schema is een middel, geen doel. Wie nooit durft te pauzeren, is niet gedisciplineerd maar star. Juist het vermogen om bewust een stap terug te doen bij drukte, ziekte of een dip laat zien dat jij het schema stuurt en niet andersom. Na een pauze pak je de draad gewoon weer op.',array['fast_mid','fast_late']::text[],null,true,'Beslis nu bewust: vandaag doorgaan of pauzeren, en sta achter die keuze.',null),
('valk-b-09','valkuilen','Als het schema wint van je gezin','Herken je dit: je slaat het zwemmen op zaterdagochtend over omdat er daarna pannenkoeken zijn, of je schuift een uitje door omdat het niet in je venster past. Af en toe plannen is prima. Maar zodra vasten structureel bepaalt welke momenten je met je kinderen meemaakt, staat het middel boven het doel. Je bent hieraan begonnen om een fittere vader te zijn, niet een afwezige. Tel eens na hoeveel gezinsmomenten je de afgelopen maand hebt aangepast aan je schema. Meer dan een paar? Dan is het schema te strak.',array['fast_early','fast_mid']::text[],null,false,null,null),
('valk-b-10','valkuilen','De flexibiliteitstest','Stel jezelf één vraag: kun je morgen zonder wroeging je vast breken als daar een goede reden voor is? Een verjaardagsontbijt, een zieke nacht, een dag waarop het gewoon niet gaat. Als het antwoord ja is, gebruik je vasten als gereedschap. Voelt het idee alleen al als falen, of levert het onrust en schuldgevoel op, dan is de regel belangrijker geworden dan jij. Dat is het moment om je verhouding tot het schema te herzien, eventueel samen met iemand die je vertrouwt.',array['any']::text[],null,false,null,null),
('valk-b-11','valkuilen','Je kinderen als meetlat','In de eerste weken wat prikkelbaar zijn tijdens de vastenuren is normaal; je lichaam moet wennen. Maar zit je er maanden in en eindigt het avondritueel met de kinderen nog steeds geregeld in snauwen, dan past het schema niet bij je leven. Kinderen merken feilloos wanneer je er niet echt bent. Gebruik ze als eerlijke meetlat: word je door het vasten een rustiger vader of een kortere? In het tweede geval is een milder venster geen concessie, maar de juiste correctie.',array['fast_early','fast_late']::text[],null,false,null,null),
('valk-b-12','valkuilen','Het verschil tussen afzien en alarm','Maak voor jezelf het onderscheid tussen afzien en alarm. Gewone honger is vervelend maar zakt na een kwartier meestal weg, zeker als je iets anders gaat doen. Aanhoudende duizeligheid, hartkloppingen of wazig zicht zakken niet weg en horen niet bij gezond vasten. Zwaar betekent: doorkomen kan, met afleiding en water. Alarm betekent: nu eten, zonder onderhandeling met jezelf. Dit onderscheid is je veiligheidsklep. Wie het scherp heeft, kan streng zijn voor zichzelf zonder onverstandig te worden.',array['fast_mid','fast_late']::text[],null,true,'Zet een timer op vijftien minuten en beoordeel daarna opnieuw hoe je je voelt.',null),
('valk-b-13','valkuilen','Een verleden met eetproblemen telt mee','Heb je vroeger geworsteld met eetbuien, streng lijnen of een eetstoornis, wees dan extra alert. Vasten draait om regels rond eten, en juist dat patroon kan oud gedrag wakker maken. Dit geldt ook voor mannen; het beeld dat eetstoornissen alleen vrouwen treffen klopt niet. Merk je dat oude gedachten terugkomen, dat eten weer beladen wordt of dat je gaat compenseren, stop dan met vasten en bespreek het met je huisarts. Er zijn genoeg andere manieren om aan je gezondheid te werken.',array['any']::text[],null,false,null,null),
('valk-b-14','valkuilen','Slik je medicijnen? Eerst de huisarts','Gebruik je medicatie voor diabetes, bloeddruk of iets anders dat op vaste tijden of met voedsel ingenomen moet worden, begin dan niet op eigen houtje. Vasten verandert je bloedsuiker en soms de werking van medicijnen; vooral bij bloedsuikerverlagende middelen kan dat gevaarlijk uitpakken. Ook zonder medicatie is er een lijst waarbij overleg verstandig is: flauwvallen, aanhoudende hartkloppingen, snel en onbedoeld gewichtsverlies, of gedachten over eten die je niet meer loslaten. De huisarts kijkt er nuchter naar. Eén gesprek kost je een halfuur en voorkomt gedoe.',array['any']::text[],null,false,null,null),
('zwaar-01','mindset','Deze golf is over een kwartier weg','Wat je nu voelt is geen stijgende lijn die alleen maar erger wordt. Honger bouwt op, piekt en zakt daarna vanzelf weer weg, ook als je niets eet. Meestal binnen een kwartier tot twintig minuten. Je hoeft dit gevoel dus niet op te lossen; je hoeft het alleen uit te zitten. En uitzitten gaat een stuk makkelijker met iets in je handen dan met niets.',array['fast_mid','fast_late']::text[],null,true,'Drink een groot glas water en wacht de golf uit.',null),
('zwaar-02','fysiologie','Je zit nu in de uren die het meest opleveren','Juist in deze uren draait je vetverbranding op zijn hoogst. Je glycogeenvoorraad is grotendeels op en je lichaam haalt zijn energie nu vooral uit vet, precies waarvoor je dit doet. Stop je nu, dan zet je die stand weer uit en moet je morgen eerst opnieuw door de makkelijke uren voordat je hier terug bent. Doorzetten kost je vanaf hier nog een paar uur ongemak. Opgeven kost je de uren die het meest opleveren.',array['fast_late']::text[],null,true,'Zet een kop zwarte koffie.','het precieze omslagpunt naar vetverbranding verschilt per persoon en per dag'),
('zwaar-03','praktisch','Twee minuten tandenpoetsen doorbreekt de cirkel','Een oud trucje dat gewoon werkt: tandenpoetsen. De frisse smaak van tandpasta maakt de gedachte aan eten een stuk minder aantrekkelijk, en voor je hoofd is het een duidelijk signaal dat de keuken dicht is. Het kost je twee minuten. Vaak is dat genoeg om uit de kringloop van honger, koelkast, honger te stappen. En je gebit vaart er ook nog bij.',array['fast_mid','fast_late']::text[],null,true,'Poets je tanden.',null),
('zwaar-04','mindset','De rekensom van nu stoppen','Maak de rekensom even. Je hebt veertien uur of meer achter de rug; er staan er misschien nog twee of drie. Als je nu stopt, betaal je morgen opnieuw de volle prijs om op ditzelfde punt te komen: dezelfde makkelijke uren, dezelfde zware uren, alles nog een keer. Volhouden kost je vanaf hier nog een paar uur. Dat is de hele transactie. Als som bekeken is de keuze meestal snel gemaakt.',array['fast_late']::text[],null,true,'Ga tien minuten naar buiten.',null),
('zwaar-05','gezin','Ruil de golf in voor één afgemaakte klus','Er ligt vast ergens speelgoed. Of was. Of een la die al weken klemt. Pak precies één klus en maak hem af terwijl de golf over zijn piek heen gaat. Je handen zijn bezig, je hoofd heeft een taak, en over tien minuten heb je twee dingen: minder honger en één ding minder op je lijstje. Afleiding werkt het best als er iets tastbaars uit komt.',array['fast_mid']::text[],null,true,'Maak één klusje af dat al dagen ligt te wachten.',null),
('zwaar-06','praktisch','Een douche zet je hoofd op een ander spoor','Honger die blijft hangen is vaak vooral een hoofd dat in een kringetje draait. Een douche onderbreekt dat kringetje hard: andere temperatuur, ander geluid, andere prikkels op je huid. Het lukt bijna niet om over eten te blijven malen terwijl je onder de straal staat. Sluit af met tien tellen koud als je durft. Daarna sta je ergens anders in de dag dan waar je begon.',array['fast_mid','fast_late']::text[],null,true,'Neem een douche.',null),
('zwaar-07','fysiologie','Je honger loopt op de klok, niet op je maag','Het is geen toeval dat het juist nu zwaar is. Hongerhormonen zoals ghreline pieken rond de tijden waarop je gewend bent te eten. Is dit je oude lunchtijd, dan meldt je lichaam zich keurig op schema, ook al heeft het niets tekort. Handig om te weten: dit is een gewoontesignaal, geen noodsignaal. Je hoeft er niets mee, behalve hem laten passeren.',array['fast_mid']::text[],null,true,'Drink een groot glas water.','hongerpieken rond gewende eetmomenten zijn bij mensen aangetoond'),
('zwaar-08','praktisch','Niet lekker? Dan stop je, zonder schuld','Voel je je duizelig, trillerig of gewoon niet in orde, dan is dit geen moment om door te bijten. Eet iets. Zonder schuldgevoel: vasten is een hulpmiddel, geen test die je moet halen, en luisteren naar duidelijke lichamelijke signalen is verstandig, geen zwakte. Komt dit vaker terug, bespreek het dan met je huisarts voordat je verder vast. Morgen kun je gewoon opnieuw beginnen, of iets korter.',array['fast_mid','fast_late']::text[],null,true,'Eet iets kleins en ga even rustig zitten.',null),
('zwaar-09','mindset','Twintig push-ups tegen één hongergolf','Probeer dit eens: twintig push-ups, nu meteen. Niet omdat het calorieën verbrandt die ertoe doen, maar omdat je aandacht maar op één plek tegelijk kan zijn. Tijdens de inspanning is er geen ruimte voor de koelkast, en veel mensen merken dat honger na een korte krachtsinspanning even naar de achtergrond zakt. Lukken er geen twintig, doe er dan tien. Het gaat om de onderbreking, niet om de prestatie.',array['fast_mid','fast_late']::text[],null,true,'Doe twintig push-ups.',null),
('zwaar-10','mindset','Je hebt dit eerder gevoeld, en het zakte','Denk terug aan de vorige keer dat je op dit punt stond. Zwaar, hongerig, dat stemmetje dat zei dat één boterham heus niet erg was. Toen zakte het, haalde je het einde, en smaakte de eerste maaltijd beter dan welke tussendoorhap ook. Dit gevoel is niet nieuw en het is niet blijvend. Het bewijs heb je al geleverd; vandaag hoef je het alleen te herhalen.',array['fast_late']::text[],null,true,'Loop een blokje om.',null),
('zwaar-11','praktisch','Besluit nu wat je straks eet, en het malen stopt','Veel van de zwaarte in de laatste uren is gemaal: wat ga ik eten, wanneer, hoeveel. Dat gemaal stopt zodra het besluit genomen is. Bepaal nu precies wat je eerste maaltijd wordt en hoe laat je hem eet. Schrijf het op of leg de ingrediënten alvast klaar. Je hoofd hoeft dan niet meer te onderhandelen; het hoeft alleen te wachten op een tijdstip dat al vaststaat.',array['fast_late']::text[],null,true,'Schrijf op wat je eerste maaltijd wordt.',null),
('zwaar-12','fysiologie','Dit ongemak is de stand, geen storing','Er gaat niets mis in je lijf op dit moment. Je insuline is laag, je lichaam schakelt over op zijn eigen voorraad, en dat schakelen voel je nu eenmaal. Het is precies de stand waarvoor je deze vast begonnen bent; alleen krijg je hem niet gratis. Vergelijk het met spierpijn na het sporten: onprettig, maar het hoort bij het proces in plaats van dat het ertegen ingaat.',array['fast_mid','fast_late']::text[],null,true,'Drink een glas bruiswater.',null),
('zwaar-13','gezin','Zeg tegen je partner dat het een taaie dag is','Zwaar dragen gaat makkelijker als iemand het weet. Stuur je partner een kort bericht: vandaag is een taaie, ik zit er middenin. Meer hoeft niet. Het hardop maken haalt de druk eraf, en de kans is groot dat je er vanavond een vraag over krijgt in plaats van dat je het venster stiekem eerder opent. Een getuige maakt volhouden concreter dan wilskracht alleen.',array['fast_mid']::text[],null,true,'Stuur je partner nu dat bericht.',null),
('zwaar-14','mindset','Vijf dingen zien, vier horen, drie voelen','Een techniek uit de gereedschapskist tegen piekeren, en hij werkt ook tegen hongergedachten: benoem in stilte vijf dingen die je ziet, vier die je hoort, drie die je voelt, twee die je ruikt en één die je proeft. Je aandacht kan niet tegelijk bij die oefening en bij de koelkast zijn. Klinkt simpel, is het ook. Daarom werkt het juist als je hoofd te vol zit.',array['fast_mid','fast_late']::text[],null,true,'Doe de oefening nu, van vijf tot en met één.',null),
('zwaar-15','fysiologie','Je tank is voller dan je maag beweert','Het lege gevoel in je maag is geen brandstofmeter. Zelfs een slanke man draagt tienduizenden kilocalorieën aan vet met zich mee, genoeg voor dagen tot weken zonder eten. Waar je nu tegenaan loopt is dus geen lichaam zonder energie, maar een lichaam dat moet wennen aan een andere aanvoerroute. De voorraad is er. De golf die je voelt zegt daar niets over.',array['fast_mid','fast_late']::text[],null,true,'Vul een fles water en drink hem het komende uur leeg.',null),
('zwaar-16','gezin','Jassen aan, buiten wint de koektrommel niet','Half vier, de kinderen hangen aan je broek en de koektrommel staat op ooghoogte. Dit is het moment waarop binnen blijven verliezen is. Jassen aan, naar buiten, desnoods maar tien minuten naar de speeltuin of het grasveldje. Buitenlucht en beweging drukken de golf naar de achtergrond, de kinderen raken hun energie kwijt, en op straat staat nergens een koektrommel.',array['fast_mid']::text[],null,true,'Ga met de kinderen tien minuten naar buiten.',null),
('zwaar-17','mindset','Stoppen is een beslissing, geen nederlaag','Stoppen mag ook. Niet als noodrem voor een lastig kwartier, maar als bewuste beslissing op een dag die er echt niet in zit. Merk je dat het vasten je humeur zo drukt dat je gezin ervan meekrijgt, open het venster dan eerder en doe dat zonder schuldgevoel. Eén aangepaste dag zegt niets over jou of over je aanpak. De afspraak met jezelf staat er morgen gewoon weer.',array['fast_mid','fast_late']::text[],null,true,'Eet rustig iets aan tafel, zittend, niet bij het aanrecht.',null),
('zwaar-18','mindset','Geef je honger een cijfer en meet opnieuw','Geef je honger een cijfer van één tot tien. Wees eerlijk; meestal is het geen negen maar een zes. Doe daarna tien minuten iets met je handen en geef opnieuw een cijfer. Bijna altijd is het gezakt, en dat is precies het punt: je meet dan zelf dat dit gevoel beweegt in plaats van vaststaat. En wat beweegt, kun je uitzitten.',array['fast_mid','fast_late']::text[],null,true,'Ruim de vaatwasser uit en geef daarna opnieuw een cijfer.',null),
('zwaar-19','fysiologie','Volgende week is deze golf kleiner','Deze golf staat niet vast op dit tijdstip. Houd je je eetvenster een aantal dagen op rij aan, dan schuiven je hongersignalen mee met het nieuwe ritme en wordt precies dit moment van de dag merkbaar rustiger. Elke keer dat je nu niet toegeeft, train je dat ritme. Vandaag doorstaan is dus niet alleen vandaag winnen; het maakt volgende week letterlijk lichter.',array['fast_mid']::text[],null,true,'Zet een kop zwarte koffie of thee.','verschuiving van hongerpatronen is bij mensen beschreven, maar individuele verschillen zijn groot'),
('zwaar-20','praktisch','Het laatste uur duurt het langst, gebruik het','Het laatste uur voelt vaak het langst, net als de laatste kilometers van een lange rit. Dat is aandacht, geen nood: hoe dichter bij het venster, hoe meer je hoofd erop vooruitloopt. Gebruik die energie ergens voor. Dek de tafel, snijd de groente, zet alles klaar voor de eerste maaltijd. Zo ben je bezig mét eten in plaats van vechten tégen eten, en de tijd loopt vanzelf door.',array['fast_late']::text[],null,true,'Dek alvast de tafel voor de eerste maaltijd.',null),
('sport-c-01','sport','Na je training: eiwit, geen paniek over timing','De belangrijkste vraag na een training is niet wanneer je eet, maar wat. Mik op 20 tot 40 gram eiwit in je eerstvolgende maaltijd: kwark, eieren, kip, vis of een shake. Valt je training vlak voor je venster, dan is je eerste maaltijd meteen je herstelmaaltijd. Dat is precies waarom trainen vlak voor de vensteropening zo goed werkt.',array['eat_open']::text[],true,false,null,null),
('sport-c-02','sport','Isotone drank tijdens je vast: nee','Een isotone sportdrank zit vol suiker — dat is het hele punt van isotoon. Drink je hem tijdens je vast, dan stijgt je insuline en is je vast gebroken. Wil je tijdens het sporten in je vastenuren iets anders dan water, kies dan water met een snufje zout of een elektrolytenpoeder zonder suiker en zonder calorieën. Check het etiket: nul koolhydraten is de eis.',array['any']::text[],true,false,null,null),
('sport-c-03','sport','Isotone drank in je venster: mag, zelden nodig','Na een lange of zware sessie — ruim een uur flink zweten — is een isotone drank in je eetvenster prima: hij vult vocht, zout en suikers snel aan. Maar voor de meeste trainingen van drie kwartier in de sportschool is hij overbodig. Een gewone maaltijd met water erbij doet hetzelfde, zonder de extra suikercalorieën. Bewaar isotoon voor de echt lange dagen.',array['eat_open','eat_mid']::text[],true,false,null,null),
('sport-c-04','sport','Je eerste maaltijd na het sporten','Simpel stramien voor de maaltijd na je training: een flinke portie eiwit, koolhydraten om je voorraad aan te vullen, en ruim drinken. Denk aan kip met rijst en groente, een omelet met brood, of kwark met havermout en fruit. Geen speciale sportproducten nodig. Gewoon eten doet negentig procent van het werk, ook als je even in de vast hebt getraind.',array['eat_open']::text[],true,false,null,null),
('sport-c-05','sport','Zweet is water plus zout','Wat je met zweten verliest is vooral vocht en natrium. Na een training in je vastenuren vul je dat aan met water en een snufje zout of een kop bouillon — dat breekt je vast niet en scheelt hoofdpijn en futloosheid. De rest van je mineralen komt vanzelf binnen zodra je venster opent en je normaal eet.',array['any']::text[],true,false,null,null),
('sport-c-06','sport','Het anabole venster is ruimer dan je denkt','Het idee dat je binnen dertig minuten na krachttraining eiwit móét nemen, is achterhaald. Je spieren blijven vele uren gevoelig voor opbouw. Train je nuchter en eet je pas twee of drie uur later, dan is dat voor spierbehoud geen ramp — zolang je over de hele dag genoeg eiwit binnenkrijgt. Veel langer wachten dan een paar uur na zwaar trainen is wel onhandig; plan daarom je training richting je venster.',array['any']::text[],true,false,null,'onderzoek wijst op een venster van meerdere uren, niet minuten'),
('sport-c-07','sport','Dorst na de training: eerst water, dan eten','Direct na het sporten voelt honger en dorst als één grote schreeuw. Begin met een groot glas water en wacht vijf minuten. Vaak blijkt de helft van de honger gewoon dorst te zijn. Daarna rustig eten in plaats van schrokken — je hebt net getraind, de winst weggooien met een eetbui is zonde.',array['eat_open']::text[],true,false,null,null),
('sport-c-08','sport','Melk of een shake: snel en genoeg','Geen tijd voor een echte maaltijd na je training? Een halve liter melk of een eiwitshake met een banaan is een prima tussenoplossing: eiwit, vocht en koolhydraten in één klap. Niet chiquer dan nodig. De volwaardige maaltijd komt later in je venster wel.',array['eat_open','eat_mid']::text[],true,false,null,null),
('sport-c-09','sport','Suikervrije sportdrank: lees het etiket','Er bestaan sportdranken en elektrolytentabletten zonder suiker. Die kun je in je vastenuren gebruiken; ze leveren zout en mineralen zonder calorieën. Let op de kleine lettertjes: sommige "zero"-varianten bevatten toch een paar gram koolhydraten per fles. Nul gram is de norm als je je vast intact wilt houden. Zoetstoffen zijn een grijs gebied — pragmatisch gezien prima, puristisch gezien vermijd je ze.',array['any']::text[],true,false,null,null),
('sport-c-10','sport','Herstel gebeurt in je venster, niet in de kleedkamer','Spieren herstellen niet in het uur na de training maar in de 24 tot 48 uur erna — en dat herstel drijft op slaap en op wat je in je venster eet. Eén gerichte herstelmaaltijd is mooi, maar drie dagen genoeg eiwit en op tijd naar bed doen meer voor je progressie dan welk poeder dan ook. Zo werkt vasten en sporten prima samen: je eet minder vaak, niet minder goed.',array['eat_mid','eat_close']::text[],true,false,null,null)
